import { Pool } from "pg";
import crypto from "crypto";
const pool = new Pool({ connectionString: process.env.DATABASE_URL });
function hash(s: string): string { return crypto.createHash("md5").update(s.toLowerCase().trim()).digest("hex"); }
interface Q { tier:string; exam:string; qt:string; status:string; stem:string; options:string[]; correct:number[]; rationale:string; diff:number; bs:string; rs:string; sh:string; topic:string; subtopic:string; clinicalPearl:string; tags:string[]; }
function q(exam:string,bs:string,diff:number,stem:string,opts:string[],c:number,rat:string,topic:string,subtopic:string,pearl:string,tags:string[]):Q {
  return {tier:"rpn",exam,qt:"multiple_choice",status:"published",stem,options:opts,correct:[c],rationale:rat,diff,bs,rs:"BOTH",sh:hash(stem),topic,subtopic,clinicalPearl:pearl,tags};
}

const QS: Q[] = [
  // === Cardiovascular (8 questions: 3 easy, 3 moderate, 2 difficult) ===
  q("REX-PN","Cardiovascular",1,"The nurse is monitoring a client with heart failure. Which assessment finding indicates fluid volume overload?","Weight gain of 3 kg in 2 days,Dry mucous membranes,Decreased urine output with dark amber urine,Flat neck veins when supine".split(","),0,"A weight gain of 1 kg equals approximately 1000 mL of fluid retention. A 3 kg gain in 2 days signals significant fluid overload requiring diuretic adjustment and fluid restriction.","Cardiovascular","Heart Failure","Rapid weight gain is the earliest and most reliable indicator of fluid retention in heart failure clients.","heart failure,fluid overload,weight monitoring,nursing assessment".split(",")),
  q("REX-PN","Cardiovascular",2,"A client asks about reducing cholesterol through diet. The nurse recommends:","Increasing saturated fat intake for energy,Choosing lean proteins and increasing soluble fiber,Eliminating all dietary fats completely,Eating red meat daily for iron".split(","),1,"Soluble fiber (oats, beans, fruits) binds bile acids in the intestine, reducing cholesterol absorption. Lean proteins and healthy fats (olive oil, fish) help manage lipid levels alongside medication therapy.","Cardiovascular","Hyperlipidemia","Soluble fiber can reduce LDL cholesterol by 5-10% when consumed at 10-25 g per day.","cholesterol,diet,health promotion,lipid management".split(",")),
  q("REX-PN","Cardiovascular",1,"The nurse checks peripheral pulses on a client with peripheral arterial disease. Which finding is expected?","Bounding pedal pulses,Diminished or absent pedal pulses,Strong popliteal pulses,Regular radial pulses bilaterally".split(","),1,"Peripheral arterial disease causes narrowing of arteries, reducing blood flow to extremities. Diminished or absent pedal pulses reflect inadequate arterial perfusion. Additional findings include cool skin, pallor, and intermittent claudication.","Cardiovascular","Peripheral Vascular Disease","Always compare pulses bilaterally and document using a 0-3+ scale for trending.","PAD,peripheral pulses,vascular assessment,circulation".split(",")),
  q("RPN-CAT","Cardiovascular",4,"A client on a continuous heparin drip has an aPTT of 120 seconds (goal 60-80 seconds). The nurse should:","Continue the infusion at the current rate,Stop the infusion and notify the provider per protocol,Double the infusion rate to reach therapeutic range,Administer protamine sulfate immediately".split(","),1,"An aPTT of 120 seconds is significantly supratherapeutic, increasing hemorrhage risk. The heparin infusion should be stopped, the provider notified, and the aPTT rechecked per institutional nomogram before restarting at a reduced rate.","Cardiovascular","Anticoagulation Therapy","Protamine sulfate is reserved for active life-threatening bleeding, not routine aPTT elevation.","heparin,aPTT,anticoagulation,bleeding risk".split(",")),
  q("REX-PN","Cardiovascular",4,"A client with an acute ST-elevation MI arrives in the emergency department. The nurse anticipates:","Immediate cardiac catheterization for percutaneous coronary intervention within 90 minutes,Thrombolytic therapy regardless of catheterization availability,Observation for 24 hours before intervention,Echocardiogram before any treatment".split(","),0,"Door-to-balloon time of 90 minutes is the standard for PCI in STEMI. Primary PCI is preferred over thrombolytics when available within the timeframe. Delays worsen myocardial damage and mortality.","Cardiovascular","Acute Coronary Syndrome","Remember: Time is muscle. Every 30-minute delay in reperfusion increases 1-year mortality.","STEMI,PCI,emergency,reperfusion therapy".split(",")),
  q("REX-PN","Cardiovascular",3,"A client with Stage C heart failure is prescribed sacubitril-valsartan (Entresto). The nurse should verify the client has not taken which medication in the past 36 hours?","Metoprolol,An ACE inhibitor,Furosemide,Spironolactone".split(","),1,"Sacubitril-valsartan must not be given within 36 hours of an ACE inhibitor due to the risk of angioedema from combined neprilysin inhibition and ACE inhibition. This washout period is critical for patient safety.","Cardiovascular","Heart Failure Pharmacology","The 36-hour washout between ACEi and Entresto is a high-yield safety point for exams.","Entresto,ACE inhibitor,angioedema,heart failure".split(",")),
  q("REX-PN","Cardiovascular",3,"A client with stable angina uses sublingual nitroglycerin. The nurse teaches the client to:","Take one tablet and wait 15 minutes before repeating,Take one tablet every 5 minutes for up to 3 doses and call 911 if pain persists,Take 3 tablets at once for maximum effect,Swallow the tablet with water".split(","),1,"Sublingual NTG is placed under the tongue every 5 minutes for up to 3 doses. If chest pain persists after the first dose, call 911. NTG dilates coronary arteries and reduces preload. Store in dark glass container and replace every 6 months.","Cardiovascular","Angina Management","A tingling sensation under the tongue confirms potency of nitroglycerin tablets.","nitroglycerin,angina,chest pain,patient education".split(",")),

  // === Respiratory (8 questions: 3 easy, 3 moderate, 2 difficult) ===
  q("REX-PN","Respiratory",2,"A client with COPD is on 2 L/min oxygen via nasal cannula. The nurse should maintain the oxygen flow rate because:","Higher flow rates could suppress the hypoxic drive to breathe,COPD clients do not need oxygen,Low-flow oxygen increases carbon dioxide levels,Nasal cannulas cannot deliver higher rates".split(","),0,"In chronic CO2 retainers, the respiratory drive shifts from CO2 levels to low oxygen (hypoxic drive). High-flow oxygen can suppress this drive, leading to respiratory depression and CO2 narcosis.","Respiratory","COPD Management","Target SpO2 88-92% in COPD clients with chronic hypercapnia.","COPD,oxygen therapy,hypoxic drive,respiratory".split(",")),
  q("REX-PN","Respiratory",1,"The nurse teaches a client with asthma to use the rescue inhaler:","Before the controller inhaler,Only at bedtime,When experiencing acute bronchospasm symptoms,Three times daily on a schedule".split(","),2,"Rescue inhalers (short-acting beta-2 agonists like albuterol) are used PRN for acute bronchospasm. Controller medications (inhaled corticosteroids) are used daily to prevent symptoms. Using rescue inhalers more than twice per week indicates poorly controlled asthma.","Respiratory","Asthma","Needing a rescue inhaler more than 2 times per week signals inadequate asthma control.","asthma,inhaler,bronchospasm,medication teaching".split(",")),
  q("REX-PN","Respiratory",1,"The nurse positions a client with a right-sided pleural effusion for a thoracentesis. The correct position is:","Supine with arms at the sides,Sitting upright leaning forward over a bedside table,Left lateral decubitus position,Trendelenburg position".split(","),1,"The upright forward-leaning position widens the intercostal spaces on the affected side, facilitating needle insertion and fluid drainage. If the client cannot sit up, the lateral decubitus position with the affected side up is an alternative.","Respiratory","Pleural Effusion","Have the client avoid coughing during the procedure to prevent lung puncture.","thoracentesis,pleural effusion,positioning,procedure".split(",")),
  q("REX-PN","Respiratory",3,"A client on a ventilator has a high-pressure alarm sounding. The nurse should first assess for:","Disconnected tubing,Secretions in the airway or kinked tubing,A deflated endotracheal tube cuff,Low tidal volume settings".split(","),1,"High-pressure alarms indicate increased resistance in the airway circuit. Common causes include mucus plugs, bronchospasm, biting the ET tube, kinked tubing, or client coughing. Suctioning and repositioning often resolve the issue.","Respiratory","Mechanical Ventilation","High pressure = obstruction. Low pressure = leak. This mnemonic is essential for ventilator troubleshooting.","ventilator,high-pressure alarm,airway,troubleshooting".split(",")),
  q("RPN-CAT","Respiratory",4,"A client with severe ARDS has a PaO2 of 55 mmHg on 100% FiO2. The nurse anticipates:","Weaning the ventilator immediately,Prone positioning to improve oxygenation,Discontinuing oxygen therapy,Increasing the respiratory rate only".split(","),1,"Prone positioning in ARDS redistributes lung perfusion, recruits dorsal alveoli compressed by the heart and abdominal organs, and can improve oxygenation by 50-70%. It is recommended for moderate-to-severe ARDS (PaO2/FiO2 < 150) for at least 16 hours daily.","Respiratory","ARDS","Prone positioning should continue for at least 16 consecutive hours per session for maximum benefit.","ARDS,prone positioning,oxygenation,critical care".split(",")),
  q("REX-PN","Respiratory",3,"A client with cystic fibrosis is prescribed dornase alfa (Pulmozyme). The nurse explains that this medication works by:","Dilating the bronchial smooth muscle,Breaking down DNA in thick mucus to reduce viscosity,Suppressing the inflammatory response,Killing bacteria in the airways".split(","),1,"Dornase alfa is a recombinant DNase enzyme that cleaves extracellular DNA released from lysed neutrophils in CF mucus. This reduces mucus viscosity and improves pulmonary function. It is delivered via nebulizer once daily.","Respiratory","Cystic Fibrosis","Dornase alfa should not be mixed with other nebulized medications in the same treatment.","cystic fibrosis,dornase alfa,mucus,respiratory medication".split(",")),
  q("REX-PN","Respiratory",3,"A client with a tension pneumothorax presents with tracheal deviation, absent breath sounds on the affected side, and hypotension. The nurse prepares for:","Chest X-ray before any intervention,Immediate needle decompression followed by chest tube insertion,IV fluid bolus only,Administration of bronchodilators".split(","),1,"Tension pneumothorax is a life-threatening emergency requiring immediate needle decompression at the second intercostal space, midclavicular line on the affected side. This is followed by chest tube placement. Chest X-ray should not delay treatment.","Respiratory","Pneumothorax","Tension pneumothorax: treat first, image second. Tracheal deviation is a late and ominous sign.","tension pneumothorax,needle decompression,emergency,chest tube".split(",")),

  // === Neurological (8 questions: 3 easy, 3 moderate, 2 difficult) ===
  q("REX-PN","Neurological",1,"A client with a stroke has dysphagia. Before offering oral fluids, the nurse should first:","Encourage the client to drink water slowly,Perform a bedside swallowing assessment or obtain a speech therapy consult,Place the client flat in bed,Offer thin liquids through a straw".split(","),1,"Dysphagia after stroke increases aspiration risk. A swallowing assessment is essential before any oral intake. Speech-language pathologists determine the safest diet consistency. Thin liquids are often the most aspirated texture.","Neurological","Stroke/CVA","Thin liquids are the highest aspiration risk for dysphagic clients — always thicken first.","stroke,dysphagia,swallowing,aspiration prevention".split(",")),
  q("REX-PN","Neurological",1,"The nurse assesses a client with meningitis. The classic triad of symptoms includes:","Headache and fever with neck stiffness,Vision changes and hearing loss and dizziness,Chest pain and shortness of breath and palpitations,Abdominal pain and nausea and diarrhea".split(","),0,"Bacterial meningitis presents with the classic triad of severe headache, high fever, and nuchal rigidity (stiff neck). Positive Kernig and Brudzinski signs confirm meningeal irritation. Photophobia and altered consciousness are also common.","Neurological","Meningitis","Kernig sign: pain with leg extension at the knee when hip is flexed. Brudzinski sign: involuntary hip/knee flexion when neck is flexed.","meningitis,nuchal rigidity,Kernig sign,Brudzinski sign".split(",")),
  q("REX-PN","Neurological",1,"A client taking levodopa-carbidopa for Parkinson disease should be taught to avoid:","All fruits and vegetables,High-protein meals taken at the same time as the medication,Drinking water with the medication,Light physical activity".split(","),1,"High-protein intake competes with levodopa for absorption in the intestine and at the blood-brain barrier, reducing medication effectiveness. Protein should be distributed throughout the day or consumed mainly at dinner to optimize levodopa's effects.","Neurological","Parkinson Disease","Distribute protein intake to evening meals to minimize interference with daytime levodopa doses.","Parkinson disease,levodopa,protein,medication-food interaction".split(",")),
  q("REX-PN","Neurological",3,"A client post-craniotomy develops diabetes insipidus. The nurse expects to find:","Decreased urine output with concentrated urine,Large volumes of dilute urine with elevated serum sodium,Hypoglycemia and polyuria,Peripheral edema and weight gain".split(","),1,"Craniotomy near the pituitary can damage the posterior pituitary, reducing ADH secretion. This causes massive dilute urine output (up to 20 L/day), hypernatremia, and dehydration. Treatment includes desmopressin (DDAVP) and fluid replacement.","Neurological","Diabetes Insipidus","Specific gravity < 1.005 with urine output > 200 mL/hr signals DI in post-neurosurgery clients.","diabetes insipidus,craniotomy,ADH,desmopressin".split(",")),
  q("RPN-CAT","Neurological",4,"A client with myasthenia gravis on pyridostigmine develops increased weakness, bradycardia, and excessive salivation. The nurse suspects:","Myasthenic crisis requiring more pyridostigmine,Cholinergic crisis from medication excess,Normal disease progression,Unrelated cardiac event".split(","),1,"Cholinergic crisis results from excessive anticholinesterase medication causing overstimulation at the neuromuscular junction. Symptoms include SLUDGE (salivation, lacrimation, urination, defecation, GI cramping, emesis) plus bradycardia and muscle weakness. The Tensilon test differentiates from myasthenic crisis.","Neurological","Myasthenia Gravis","SLUDGE mnemonic identifies cholinergic excess. Atropine is the antidote for cholinergic crisis.","myasthenia gravis,cholinergic crisis,pyridostigmine,SLUDGE".split(",")),
  q("REX-PN","Neurological",3,"A client with a spinal cord injury at T6 develops a pounding headache, bradycardia, and severe hypertension. The nurse should first:","Administer IV antihypertensives,Sit the client upright and check for bladder distension or other noxious stimuli below the injury,Place the client in Trendelenburg position,Administer aspirin for headache".split(","),1,"Autonomic dysreflexia is a life-threatening emergency in SCI at T6 or above. Sitting upright lowers BP through orthostatic effect. Identifying and removing the trigger (usually bladder distension from kinked catheter, fecal impaction, or tight clothing) is essential.","Neurological","Spinal Cord Injury","The most common trigger for autonomic dysreflexia is bladder distension — always check the catheter first.","autonomic dysreflexia,spinal cord injury,hypertension,emergency".split(",")),
  q("REX-PN","Neurological",3,"A client with Guillain-Barré syndrome reports progressive ascending weakness that has reached the thighs. The nurse's priority assessment is:","Cranial nerve function,Respiratory function including vital capacity and negative inspiratory force,Bowel sounds,Deep tendon reflexes".split(","),1,"GBS causes ascending paralysis that can compromise respiratory muscles. Vital capacity below 20 mL/kg and negative inspiratory force weaker than -20 cmH2O predict the need for mechanical ventilation. Respiratory monitoring is the priority as the weakness ascends.","Neurological","Guillain-Barré Syndrome","The 20/30/40 rule: intubate if VC < 20, NIF < -30, or VC decline > 30% from baseline.","Guillain-Barré,respiratory failure,ascending paralysis,vital capacity".split(",")),

  // === Endocrine (7 questions: 3 easy, 2 moderate, 2 difficult) ===
  q("REX-PN","Endocrine",1,"A client with hypothyroidism is started on levothyroxine. The nurse instructs the client to take the medication:","At bedtime with a large meal,On an empty stomach 30-60 minutes before breakfast,With calcium supplements for absorption,Crushed and mixed with dairy products".split(","),1,"Levothyroxine absorption is decreased by food, calcium, iron, and antacids. Taking it on an empty stomach 30-60 minutes before breakfast maximizes absorption. Consistent timing is important for stable thyroid levels.","Endocrine","Hypothyroidism","Wait at least 4 hours between levothyroxine and calcium or iron supplements.","levothyroxine,hypothyroidism,medication administration,thyroid".split(",")),
  q("REX-PN","Endocrine",1,"The nurse teaches a client with type 2 diabetes about the importance of HbA1c testing. This test reflects:","Blood glucose at the time of the test,Average blood glucose over the past 2-3 months,Fasting insulin levels,Kidney function related to diabetes".split(","),1,"Hemoglobin A1c measures the percentage of glycosylated hemoglobin, reflecting average blood glucose over 2-3 months (the lifespan of red blood cells). The ADA target for most adults is < 7%. Each 1% reduction decreases microvascular complications by ~30%.","Endocrine","Diabetes Mellitus","HbA1c of 7% correlates to an average glucose of approximately 154 mg/dL.","HbA1c,diabetes,blood glucose,monitoring".split(",")),
  q("REX-PN","Endocrine",1,"A client with Cushing syndrome would exhibit which characteristic physical appearance?","Thin face with prominent cheekbones,Moon face with central obesity and buffalo hump,Uniform weight loss with dark skin,Exophthalmos with goiter".split(","),1,"Excess cortisol in Cushing syndrome causes central obesity, moon face (round), buffalo hump (dorsocervical fat pad), thin extremities, striae, easy bruising, and hirsutism. Treatment depends on the cause (tumor resection, medication adjustment).","Endocrine","Cushing Syndrome","Remember Cushing: Cortisol excess causes Central obesity, moon faCe, and thin skin.","Cushing syndrome,cortisol,physical assessment,endocrine".split(",")),
  q("REX-PN","Endocrine",3,"A client in diabetic ketoacidosis has a serum potassium of 5.8 mEq/L. The nurse understands this elevated potassium:","Indicates true potassium excess requiring urgent treatment,May be falsely elevated due to acidosis-induced intracellular potassium shift and will decrease with insulin therapy,Is unrelated to the DKA,Requires immediate dialysis".split(","),1,"In DKA, acidosis causes hydrogen ions to move into cells in exchange for potassium (shifting K+ out), creating a falsely elevated serum potassium despite total body potassium depletion. Insulin therapy drives potassium back into cells, potentially causing life-threatening hypokalemia.","Endocrine","Diabetic Ketoacidosis","Always check potassium before starting insulin in DKA — replacing K+ prevents fatal hypokalemia.","DKA,potassium,acidosis,insulin therapy".split(",")),
  q("RPN-CAT","Endocrine",4,"A client with acromegaly reports headaches and visual field deficits. The nurse understands these symptoms are caused by:","Elevated growth hormone directly,Pituitary adenoma compression of the optic chiasm,Diabetic retinopathy,Increased intracranial pressure from hydrocephalus".split(","),1,"Acromegaly results from a GH-secreting pituitary adenoma. As the tumor enlarges, it compresses the optic chiasm causing bitemporal hemianopia (loss of peripheral vision bilaterally). Headaches result from tumor pressure. Treatment is transsphenoidal surgery.","Endocrine","Acromegaly","Bitemporal hemianopia (tunnel vision) is the classic visual field deficit of pituitary tumors compressing the optic chiasm.","acromegaly,pituitary adenoma,optic chiasm,visual field".split(",")),
  q("REX-PN","Endocrine",3,"A client post-thyroidectomy develops tingling around the mouth and carpopedal spasms. The nurse suspects:","Anxiety reaction,Hypocalcemia from inadvertent parathyroid gland removal,Hypomagnesemia,Thyroid storm".split(","),1,"The parathyroid glands embedded in the thyroid may be damaged during thyroidectomy, causing hypoparathyroidism and hypocalcemia. Positive Chvostek sign (facial twitching with tap) and Trousseau sign (carpopedal spasm with BP cuff) confirm hypocalcemia. IV calcium gluconate is the treatment.","Endocrine","Post-Thyroidectomy Complications","Keep IV calcium gluconate at bedside post-thyroidectomy. Check Chvostek and Trousseau signs every 4 hours.","thyroidectomy,hypocalcemia,parathyroid,Chvostek sign".split(",")),
  q("REX-PN","Endocrine",3,"A client with Addison disease experiencing an addisonian crisis should receive:","Fluid restriction and potassium supplementation,IV hydrocortisone and aggressive IV normal saline replacement,Oral prednisone taper,Insulin administration".split(","),1,"Addisonian crisis is an acute adrenal insufficiency emergency. Treatment includes IV hydrocortisone (stress dose 100 mg bolus), aggressive IV NS for volume expansion (may need 2-3 L in the first hours), vasopressors if needed, and identification of the precipitating cause (infection, missed doses).","Endocrine","Adrenal Insufficiency","Addisonian crisis: Think 3 S's — Salt (IV NS), Sugar (D5NS if hypoglycemic), Steroids (IV hydrocortisone).","Addison disease,adrenal crisis,hydrocortisone,emergency".split(",")),

  // === Gastrointestinal (7 questions: 3 easy, 2 moderate, 2 difficult) ===
  q("REX-PN","Gastrointestinal",1,"A client with gastroesophageal reflux disease (GERD) should be taught to:","Lie down immediately after eating,Avoid eating 2-3 hours before bedtime and elevate the head of bed,Drink carbonated beverages to aid digestion,Wear tight-fitting clothing to support the abdomen".split(","),1,"GERD management includes avoiding meals before bedtime (gravity helps prevent reflux), HOB elevation 6-8 inches, avoiding triggers (caffeine, spicy foods, alcohol, chocolate), weight loss, and not wearing tight clothing around the waist.","Gastrointestinal","GERD","Elevate the head of bed with blocks — not just pillows, which can increase abdominal pressure.","GERD,reflux,lifestyle modification,patient education".split(",")),
  q("REX-PN","Gastrointestinal",1,"The nurse is caring for a client with a nasogastric tube connected to low intermittent suction. Which electrolyte imbalance should the nurse monitor for?","Hyperkalemia,Metabolic alkalosis with hypokalemia and hypochloremia,Respiratory acidosis,Hypernatremia".split(","),1,"NG suction removes hydrochloric acid (H+, Cl-, K+) from the stomach, leading to metabolic alkalosis from H+ loss, hypokalemia from K+ loss, and hypochloremia from Cl- loss. Monitor electrolytes and replace as ordered.","Gastrointestinal","Nasogastric Tube Management","NG suction losses: Think HCl — you lose H+ (alkalosis), Cl- (hypochloremia), and K+ (hypokalemia).","NG tube,electrolyte imbalance,metabolic alkalosis,suction".split(",")),
  q("REX-PN","Gastrointestinal",1,"A client recovering from an appendectomy asks when they can resume a normal diet. The nurse explains that diet advancement depends on:","A specific number of days post-surgery,Return of bowel sounds and passage of flatus indicating return of peristalsis,The surgeon's personal preference only,The client's appetite".split(","),1,"Post-abdominal surgery, diet advancement follows return of GI function: auscultation of bowel sounds in all four quadrants and passage of flatus indicate peristalsis has resumed. Diet is advanced from clear liquids to regular as tolerated.","Gastrointestinal","Post-Surgical Care","Absence of bowel sounds for 5 minutes in each quadrant constitutes absent bowel sounds.","appendectomy,bowel sounds,diet advancement,post-operative".split(",")),
  q("REX-PN","Gastrointestinal",3,"A client with acute pancreatitis has severe epigastric pain. The nurse should position the client in:","Supine with legs extended flat,Side-lying with knees flexed toward the chest,Prone position,High Fowler's position with legs down".split(","),1,"The fetal position (side-lying with knees drawn up) reduces tension on the abdominal muscles and peritoneum, providing pain relief in pancreatitis. NPO status, IV fluids, pain management, and NG tube placement for vomiting are additional interventions.","Gastrointestinal","Pancreatitis","Pancreatitis pain management: position, NPO, meperidine or hydromorphone (avoid morphine — may cause sphincter of Oddi spasm).","pancreatitis,pain management,positioning,nursing care".split(",")),
  q("RPN-CAT","Gastrointestinal",4,"A client with ulcerative colitis is prescribed infliximab. Before starting the medication, the nurse should verify:","Normal liver function tests only,Negative tuberculosis screening test,Complete blood count only,Stool culture results".split(","),1,"Infliximab is a TNF-alpha inhibitor that suppresses immune function and can reactivate latent tuberculosis. Screening with a tuberculin skin test or interferon-gamma release assay is mandatory before initiating any anti-TNF therapy. Hepatitis B screening is also required.","Gastrointestinal","Inflammatory Bowel Disease","All anti-TNF agents (infliximab, adalimumab) require TB and hepatitis B screening before initiation.","infliximab,TNF inhibitor,tuberculosis screening,ulcerative colitis".split(",")),
  q("REX-PN","Gastrointestinal",3,"A client with hepatic encephalopathy is prescribed lactulose. The nurse should titrate the dose to achieve:","One formed bowel movement daily,Two to three soft stools per day to reduce ammonia levels,No bowel movements to rest the intestine,Watery diarrhea six or more times daily".split(","),1,"Lactulose is an osmotic laxative that traps ammonia in the colon for excretion. The dose is titrated to produce 2-3 soft stools daily. Too many stools cause dehydration and electrolyte imbalance; too few allow ammonia to accumulate.","Gastrointestinal","Hepatic Encephalopathy","Monitor for hypokalemia with lactulose — potassium loss from diarrhea can worsen hepatic encephalopathy.","lactulose,hepatic encephalopathy,ammonia,dose titration".split(",")),
  q("REX-PN","Gastrointestinal",3,"A client with a Sengstaken-Blakemore tube for esophageal variceal bleeding must have which equipment at bedside?","Suction machine only,Scissors to cut the tube in case of airway obstruction,Extra IV tubing,Heating pad".split(","),1,"The esophageal balloon can migrate and obstruct the airway. Scissors at bedside allow immediate tube transection to deflate the balloon and restore the airway in an emergency. This is a critical safety measure for any client with a balloon tamponade tube.","Gastrointestinal","Variceal Bleeding","If a Blakemore tube migrates upward and the client becomes dyspneic, cut the tube immediately — do not attempt repositioning.","Blakemore tube,esophageal varices,airway safety,emergency equipment".split(",")),

  // === Pharmacology (8 questions: 3 easy, 3 moderate, 2 difficult) ===
  q("REX-PN","Pharmacology",1,"The nurse is preparing to administer a medication. The five rights of medication administration include:","Right client, right drug, right dose, right route, right time,Right client, right color, right size, right label, right cost,Right doctor, right pharmacy, right client, right insurance, right reason,Right client, right nurse, right shift, right unit, right form".split(","),0,"The five rights are a safety framework: right client (two identifiers), right drug, right dose, right route, right time. Additional rights include right documentation, right reason, right to refuse, and right assessment before and after administration.","Pharmacology","Medication Safety","Many facilities now teach 9 or 10 rights — but the original 5 are the exam foundation.","medication safety,five rights,drug administration,nursing fundamentals".split(",")),
  q("REX-PN","Pharmacology",1,"A client asks why they must complete the full course of antibiotics even if they feel better. The nurse explains:","The medication loses effectiveness after a few days,Stopping early promotes antibiotic-resistant organisms,Extra pills should be saved for future illness,The pharmacy requires proof of completion".split(","),1,"Incomplete antibiotic courses kill susceptible bacteria but leave resistant organisms to multiply, creating antibiotic-resistant strains. Completing the prescribed course ensures eradication of the infection and prevents resistance development.","Pharmacology","Antibiotic Therapy","Antibiotic resistance is one of the greatest public health threats — adherence education is essential.","antibiotics,drug resistance,patient education,adherence".split(",")),
  q("REX-PN","Pharmacology",1,"Before administering metformin, the nurse should check:","Serum sodium levels,Renal function (serum creatinine and GFR),Coagulation studies,Liver enzymes only".split(","),1,"Metformin is contraindicated in renal impairment (eGFR < 30 mL/min) due to the risk of lactic acidosis. Renal function should be assessed before initiation and at least annually. Hold before contrast dye procedures and restart after renal function is confirmed.","Pharmacology","Antidiabetic Medications","Hold metformin 48 hours before and after iodinated contrast to prevent contrast-induced lactic acidosis.","metformin,renal function,lactic acidosis,diabetes".split(",")),
  q("REX-PN","Pharmacology",3,"A client is prescribed amiodarone for atrial fibrillation. The nurse should monitor for:","Hypothyroidism or hyperthyroidism and pulmonary toxicity,Hyperglycemia only,Renal failure as the primary concern,Weight loss and diarrhea".split(","),0,"Amiodarone contains iodine and can cause both hypothyroidism and hyperthyroidism. It also causes pulmonary fibrosis (monitor with periodic chest X-rays and PFTs), hepatotoxicity, corneal microdeposits, and skin photosensitivity (blue-gray discoloration).","Pharmacology","Antiarrhythmics","Amiodarone affects virtually every organ — remember the mnemonic: Lungs, Liver, Thyroid, Eyes, Skin.","amiodarone,thyroid toxicity,pulmonary fibrosis,antiarrhythmic".split(",")),
  q("RPN-CAT","Pharmacology",4,"A client on lithium therapy has a level of 2.1 mEq/L. The nurse should:","Administer the next dose as scheduled,Hold the lithium and prepare for possible dialysis as this is a toxic level,Reduce the dose by half,Give a sodium supplement".split(","),1,"Lithium therapeutic range is 0.6-1.2 mEq/L. Levels > 1.5 are toxic; > 2.0 are severely toxic, causing seizures, coma, cardiac dysrhythmias, and renal failure. Hold lithium, notify the provider, increase IV fluids, and prepare for hemodialysis. Sodium depletion increases lithium toxicity.","Pharmacology","Mood Stabilizers","Dehydration and NSAIDs increase lithium levels — these are the most common causes of lithium toxicity.","lithium,toxicity,therapeutic range,hemodialysis".split(",")),
  q("REX-PN","Pharmacology",3,"A client receiving IV aminoglycoside therapy (gentamicin) should have which laboratory values monitored?","Liver function tests,Peak and trough drug levels along with serum creatinine and BUN,Serum glucose levels,PT and INR".split(","),1,"Aminoglycosides are nephrotoxic and ototoxic. Peak levels (drawn 30 min after infusion) ensure efficacy; trough levels (drawn before next dose) ensure toxicity avoidance. BUN and creatinine monitor renal function. Report tinnitus or hearing changes immediately.","Pharmacology","Aminoglycoside Therapy","Trough levels are drawn just before the next dose — this is the most important level for preventing toxicity.","gentamicin,aminoglycoside,peak and trough,nephrotoxicity".split(",")),
  q("REX-PN","Pharmacology",3,"A client on carbamazepine develops a widespread blistering rash. The nurse should:","Apply topical corticosteroids and continue the medication,Discontinue the medication immediately and notify the provider,Reduce the dose and monitor,Switch to a different formulation of carbamazepine".split(","),1,"Widespread blistering rash with carbamazepine may indicate Stevens-Johnson syndrome or toxic epidermal necrolysis, both life-threatening conditions. The drug must be stopped immediately. HLA-B*1502 testing in at-risk populations can predict this reaction.","Pharmacology","Anticonvulsants","HLA-B*1502 screening is recommended before starting carbamazepine in Asian populations due to higher SJS risk.","carbamazepine,Stevens-Johnson syndrome,drug reaction,anticonvulsant".split(",")),

  // === Mental Health (7 questions: 3 easy, 2 moderate, 2 difficult) ===
  q("REX-PN","Mental Health",1,"A client with generalized anxiety disorder is admitted to the unit. The nurse's priority intervention is to:","Teach deep breathing techniques immediately,Establish a calm and safe environment and build therapeutic rapport,Administer anxiolytics without assessment,Encourage the client to discuss childhood trauma".split(","),1,"Creating a safe, calm environment and establishing trust are foundational before any therapeutic intervention. Reducing environmental stimuli, using a calm tone, and demonstrating empathy help the anxious client feel secure and begin to engage in care.","Mental Health","Anxiety Disorders","A calm nurse creates a calm client — your demeanor is a therapeutic intervention.","anxiety,therapeutic environment,rapport,nursing intervention".split(",")),
  q("REX-PN","Mental Health",1,"The nurse is caring for a client with major depressive disorder. Which statement by the client requires immediate follow-up?","I feel sad most of the time,I have been giving away my belongings to family members,I do not enjoy cooking anymore,I have trouble sleeping at night".split(","),1,"Giving away prized possessions is a warning sign of suicidal ideation. The client may be preparing for death by settling affairs. This requires immediate suicide risk assessment including direct questioning about plans, means, and intent.","Mental Health","Depression","Giving away belongings, making a will, and saying goodbye are behavioral warning signs of imminent suicide risk.","depression,suicide warning signs,safety,assessment".split(",")),
  q("REX-PN","Mental Health",1,"Therapeutic communication involves which nursing response?","Giving personal advice based on experience,Using open-ended questions and active listening,Changing the subject when the client becomes emotional,Offering false reassurance to reduce anxiety".split(","),1,"Open-ended questions invite elaboration and exploration of feelings. Active listening demonstrates respect and promotes trust. Non-therapeutic responses include advising, false reassurance, judgmental responses, and changing the subject.","Mental Health","Therapeutic Communication","Silence is also a therapeutic technique — it allows the client time to process and formulate thoughts.","therapeutic communication,active listening,open-ended questions,nurse-client relationship".split(",")),
  q("RPN-CAT","Mental Health",4,"A client with bipolar I disorder is in the acute manic phase. The most appropriate nursing intervention for nutrition is:","Serving the client a formal sit-down meal,Providing high-calorie finger foods that can be eaten while moving,Restricting food intake to scheduled meal times,Offering only liquids until mania subsides".split(","),1,"Manic clients are hyperactive and unable to sit for meals. Providing nutritious finger foods (sandwiches, protein bars, fruit) that can be eaten while pacing maintains caloric intake. They burn significant calories and are at risk for weight loss and dehydration.","Mental Health","Bipolar Disorder","Manic clients may not recognize hunger — proactively offer food frequently throughout the day.","bipolar disorder,mania,nutrition,nursing intervention".split(",")),
  q("REX-PN","Mental Health",3,"A client diagnosed with obsessive-compulsive disorder performs handwashing rituals for 3 hours daily. The nurse should initially:","Allow time for the rituals while gradually working to reduce them,Strictly prohibit all handwashing immediately,Ignore the behavior completely,Tell the client the rituals are irrational".split(","),0,"Abruptly stopping OCD rituals causes extreme anxiety and can be counterproductive. Initially, allow the rituals while building trust. Gradually reduce time allocated for rituals through behavioral therapy techniques. Response prevention is introduced gradually with client collaboration.","Mental Health","Obsessive-Compulsive Disorder","Abrupt ritual prevention without therapeutic support increases anxiety and may cause decompensation.","OCD,rituals,anxiety,behavioral intervention".split(",")),
  q("REX-PN","Mental Health",3,"A client with borderline personality disorder repeatedly tests boundaries by making personal requests of the nurse. The most therapeutic response is:","Granting small requests to maintain the therapeutic relationship,Clearly restating the professional boundaries with consistency and empathy,Transferring the client to another nurse,Avoiding all interaction with the client".split(","),1,"Consistent boundary-setting with empathic communication is essential. BPD clients test limits due to fear of abandonment and unstable self-image. Consistency across all staff prevents splitting behavior. Empathy maintains the therapeutic relationship while enforcing limits.","Mental Health","Personality Disorders","Staff consistency is critical — hold team meetings to ensure all nurses apply the same boundaries.","BPD,boundaries,splitting,therapeutic relationship".split(",")),
  q("RPN-CAT","Mental Health",4,"A client with alcohol use disorder is admitted 24 hours after last drink and develops tremors, diaphoresis, and tachycardia. The nurse uses the CIWA scale to:","Diagnose alcohol withdrawal syndrome,Quantify withdrawal severity and guide benzodiazepine dosing,Determine blood alcohol level,Assess for liver damage".split(","),1,"The Clinical Institute Withdrawal Assessment for Alcohol (CIWA-Ar) is a 10-item scale scoring withdrawal severity. Scores guide symptom-triggered benzodiazepine administration. Scores > 20 indicate severe withdrawal with seizure and delirium tremens risk.","Mental Health","Substance Use Disorders","CIWA > 20: high seizure risk. Symptom-triggered dosing reduces total benzodiazepine use versus fixed schedules.","CIWA,alcohol withdrawal,benzodiazepine,substance use".split(",")),

  // === Pediatrics (8 questions: 3 easy, 3 moderate, 2 difficult) ===
  q("REX-PN","Pediatrics",1,"The nurse assesses a newborn using the APGAR score at 1 and 5 minutes. A score of 7-10 indicates:","Severe distress requiring resuscitation,Normal adjustment to extrauterine life,Need for supplemental oxygen,Prematurity-related complications".split(","),1,"APGAR 7-10 indicates a vigorous newborn adapting well. Scores 4-6 suggest moderate difficulty requiring stimulation and possible oxygen. Scores 0-3 indicate severe distress needing immediate resuscitation. The 5-minute score is more predictive of outcome.","Pediatrics","Newborn Assessment","The 5-minute APGAR better predicts outcomes than the 1-minute score. Continue scoring at 10 and 15 minutes if score remains < 7.","APGAR,newborn,assessment,neonatal".split(",")),
  q("REX-PN","Pediatrics",1,"A toddler is admitted for dehydration. The nurse assesses for dehydration by checking:","Blood pressure only,Skin turgor on the abdomen and anterior fontanelle status,Chest X-ray findings,Pupil responses".split(","),1,"In infants and toddlers, decreased skin turgor (tenting), sunken anterior fontanelle (if still open), dry mucous membranes, decreased tears, and decreased urine output are key dehydration indicators. Weight loss percentage quantifies severity.","Pediatrics","Fluid and Electrolyte Balance","A sunken fontanelle in an infant is a reliable sign of dehydration — check it in every dehydrated infant.","dehydration,pediatric assessment,skin turgor,fontanelle".split(",")),
  q("REX-PN","Pediatrics",1,"The nurse teaches parents about car seat safety for their 6-month-old infant. The correct instruction is:","Place the car seat forward-facing in the front seat,Use a rear-facing car seat in the back seat until age 2 or until the child exceeds the seat weight limit,No car seat is needed if a parent holds the child,Use a booster seat at this age".split(","),1,"AAP recommends rear-facing car seats until age 2 or until the child reaches the maximum height/weight limit. Rear-facing position distributes crash forces across the torso and head, protecting the vulnerable cervical spine.","Pediatrics","Safety and Injury Prevention","Rear-facing protects the infant's proportionally large head and immature cervical vertebrae in a crash.","car seat,infant safety,rear-facing,injury prevention".split(",")),
  q("REX-PN","Pediatrics",3,"A child with nephrotic syndrome has generalized edema and frothy urine. The nurse anticipates which dietary modification?","High-protein diet to replace urinary protein losses,Normal protein with sodium restriction,Fluid bolus to flush the kidneys,High-sodium diet to retain fluid".split(","),1,"Nephrotic syndrome causes massive proteinuria leading to hypoalbuminemia and edema. Dietary management includes normal protein (excess protein increases proteinuria), sodium restriction (reduces edema), and possible fluid restriction in severe cases.","Pediatrics","Renal Disorders","Excess dietary protein worsens proteinuria in nephrotic syndrome — do not give high-protein diets.","nephrotic syndrome,edema,proteinuria,diet modification".split(",")),
  q("RPN-CAT","Pediatrics",4,"A newborn with tetralogy of Fallot has a hypercyanotic (tet) spell. The nurse should immediately:","Lay the infant flat and administer oxygen,Place the infant in knee-chest position to increase systemic vascular resistance,Administer IV fluids rapidly,Obtain an echocardiogram".split(","),1,"The knee-chest position increases systemic vascular resistance, which reduces the right-to-left shunt and increases pulmonary blood flow, improving oxygenation. Additional interventions include oxygen, morphine sulfate (relaxes right ventricular outflow tract spasm), and IV fluids.","Pediatrics","Congenital Heart Disease","Knee-to-chest increases SVR, increases pulmonary blood flow, and decreases the right-to-left shunt.","tetralogy of Fallot,tet spell,knee-chest position,cyanotic heart disease".split(",")),
  q("REX-PN","Pediatrics",3,"A child with epiglottitis is drooling, sitting in a tripod position, and has a high fever. The nurse should:","Examine the throat with a tongue depressor to confirm diagnosis,Keep the child calm and avoid throat examination until airway management is available,Administer oral antibiotics immediately,Place the child supine for comfort".split(","),1,"Epiglottitis is a medical emergency. Direct throat examination with a tongue depressor can trigger complete airway obstruction. Keep the child calm, in a position of comfort (usually sitting upright), and prepare for emergency intubation or tracheostomy. Throat visualization should only occur in the OR with intubation readiness.","Pediatrics","Respiratory Emergencies","Never examine the throat of a child with suspected epiglottitis — this can cause fatal airway obstruction.","epiglottitis,airway obstruction,tripod position,emergency".split(",")),
  q("REX-PN","Pediatrics",3,"A premature neonate on mechanical ventilation develops retinopathy of prematurity. The nurse understands this is caused by:","Exposure to loud noises in the NICU,Abnormal retinal blood vessel development related to supplemental oxygen exposure,Infection acquired during delivery,Genetic condition unrelated to prematurity".split(","),1,"ROP occurs when supplemental oxygen causes abnormal blood vessel growth in the premature retina. Strict oxygen monitoring with targeted SpO2 ranges (typically 88-95% depending on gestational age) reduces ROP incidence. Screening eye exams are performed at 31 weeks gestational age.","Pediatrics","Neonatal Care","Target SpO2 88-95% in premature neonates to balance adequate oxygenation against ROP risk.","ROP,retinopathy of prematurity,oxygen,neonatal".split(",")),

  // === Fundamentals (7 questions: 3 easy, 2 moderate, 2 difficult) ===
  q("REX-PN","Fundamentals",1,"The nurse is ambulating a client who becomes lightheaded and dizzy. The nurse should:","Continue walking to the destination,Ease the client to the floor or nearest chair safely,Leave the client standing to get a wheelchair,Call a code blue immediately".split(","),1,"Easing the client down safely prevents a fall injury. The nurse lowers the client to the floor or nearest chair using proper body mechanics, stays with the client, calls for assistance, and assesses vital signs. Never leave an unsteady client unsupported.","Fundamentals","Safe Patient Handling","Widen your stance and lower your center of gravity when easing a client to the floor — protect yourself from injury too.","fall prevention,patient safety,ambulation,syncope".split(",")),
  q("REX-PN","Fundamentals",1,"When preparing to insert a urinary catheter, the nurse positions a female client in:","Prone position,Dorsal recumbent (supine with knees flexed and feet flat),Left lateral Sims position,Sitting upright".split(","),1,"The dorsal recumbent position allows optimal visualization of the urinary meatus for catheter insertion. Adequate lighting and proper landmark identification (meatus is between the clitoris and vaginal opening) prevent incorrect placement.","Fundamentals","Urinary Catheterization","If the catheter accidentally enters the vagina, leave it in place as a landmark and insert a new sterile catheter into the meatus.","urinary catheterization,female anatomy,positioning,sterile technique".split(",")),
  q("REX-PN","Fundamentals",1,"The nurse is delegating tasks to unlicensed assistive personnel. Which task is appropriate to delegate?","Initial admission assessment of a new client,Measuring and recording vital signs on a stable client,Administering IV push medications,Developing the nursing care plan".split(","),1,"Vital sign measurement on stable clients is within the UAP scope. Assessment, care planning, medication administration, and client education require licensed nurse judgment and cannot be delegated. The nurse remains accountable for all delegated tasks.","Fundamentals","Delegation","Remember the 5 Rights of Delegation: right task, right circumstance, right person, right direction, right supervision.","delegation,UAP,scope of practice,nursing leadership".split(",")),
  q("REX-PN","Fundamentals",3,"A client receiving an IV infusion develops chills, fever, headache, and nausea 30 minutes after the new IV bag was started. The nurse suspects:","Speed shock from rapid infusion,A pyrogenic reaction from contaminated IV solution,Local infiltration,Fluid volume overload".split(","),1,"Pyrogenic reaction occurs from contaminated IV solution or administration set introducing pyrogens (bacterial endotoxins) into the bloodstream. Symptoms include chills, fever, headache, nausea, and vomiting. Stop the infusion, save the bag for testing, and notify the provider.","Fundamentals","IV Therapy Complications","Save the suspected contaminated IV bag and tubing — send them to pharmacy or lab for analysis.","IV therapy,pyrogenic reaction,contamination,nursing assessment".split(",")),
  q("RPN-CAT","Fundamentals",4,"A client with a tracheostomy requires suctioning. The nurse preoxygenates with 100% oxygen for 30 seconds. During the suctioning pass, the nurse should not apply suction for longer than:","5 seconds,10-15 seconds,30 seconds,60 seconds".split(","),1,"Suctioning should last no longer than 10-15 seconds per pass to prevent hypoxia, mucosal damage, cardiac dysrhythmias, and increased intracranial pressure. Apply suction only during catheter withdrawal using a rotating motion. Allow recovery between passes.","Fundamentals","Airway Management","Apply suction only on withdrawal — never on insertion. Limit to 3 passes per suctioning episode.","tracheostomy,suctioning,hypoxia prevention,airway care".split(",")),
  q("REX-PN","Fundamentals",3,"When applying a vest restraint, the nurse must ensure that:","The restraint is tied tightly to the side rails with a square knot,The restraint allows two fingers to fit between the device and the client and is tied with a quick-release knot to a non-moveable part of the bed frame,The client is checked every 4 hours,The restraint order is renewed weekly".split(","),1,"Two-finger space prevents circulatory compromise. Quick-release knots allow emergency removal. Tied to the bed frame (not side rails) prevents injury when rails are lowered. Check circulation every 1-2 hours, provide toileting and ROM, and renew orders per policy (usually every 24 hours).","Fundamentals","Restraint Safety","Quick-release knot to the bed FRAME (not side rail). CMS requires face-to-face evaluation within 1 hour of restraint initiation.","restraints,patient safety,quick-release knot,circulation check".split(",")),
  q("REX-PN","Fundamentals",3,"A client receiving a unit of packed red blood cells develops urticaria (hives) without respiratory distress. The nurse should:","Stop the transfusion permanently,Slow the transfusion and administer diphenhydramine as prescribed,Continue the transfusion without intervention,Stop the transfusion and administer epinephrine".split(","),1,"Mild allergic reactions (urticaria, itching) without systemic symptoms can be managed by slowing the transfusion and administering an antihistamine. If symptoms progress to respiratory distress, hypotension, or anaphylaxis, the transfusion must be stopped immediately.","Fundamentals","Blood Transfusion Reactions","Mild allergic = slow rate and give antihistamine. Anaphylactic or hemolytic = STOP immediately.","blood transfusion,allergic reaction,urticaria,diphenhydramine".split(",")),

  // === Musculoskeletal (7 questions: 3 easy, 2 moderate, 2 difficult) ===
  q("REX-PN","Musculoskeletal",1,"A client with a new cast on the right arm should be instructed to:","Keep the cast below heart level at all times,Elevate the casted extremity on pillows above heart level for the first 24-48 hours,Apply heat to the cast to speed drying,Remove the cast if it feels tight".split(","),1,"Elevation above heart level reduces edema formation in the first 24-48 hours, preventing compartment syndrome and circulatory compromise. The cast should air-dry naturally. Clients should report numbness, tingling, or increased pain immediately.","Musculoskeletal","Cast Care","Teach clients to report the 5 Ps: Pain, Pallor, Pulselessness, Paresthesia, Paralysis.","cast care,elevation,edema prevention,neurovascular assessment".split(",")),
  q("REX-PN","Musculoskeletal",1,"A client with gout should avoid which dietary items?","Fresh fruits and vegetables,Organ meats and shellfish and beer,Whole grain breads,Low-fat dairy products".split(","),1,"Gout results from uric acid crystal deposition. High-purine foods (organ meats, shellfish, sardines, anchovies) and alcohol (especially beer) increase uric acid levels. Low-fat dairy, cherries, and adequate hydration help lower uric acid.","Musculoskeletal","Gout","Cherries contain anti-inflammatory compounds that may reduce gout flare frequency — a common test question.","gout,purine,uric acid,diet modification".split(",")),
  q("REX-PN","Musculoskeletal",1,"When assisting a client with a walker, the nurse instructs the client to:","Lift and place the walker two arm lengths ahead,Advance the walker one arm length ahead then step into it,Drag the walker along the floor,Lean heavily on the walker for all body weight support".split(","),1,"The walker should be advanced one arm length (about 6-10 inches), then the client steps into it, bearing weight on the handgrips. The elbows should be flexed 15-30 degrees when standing in the walker for proper height.","Musculoskeletal","Mobility Aids","Ensure walker height is correct: the top should be at the client's wrist crease when arms hang at the sides.","walker,ambulation,mobility,patient education".split(",")),
  q("REX-PN","Musculoskeletal",3,"A client post-spinal fusion should be logrolled when turning in bed. The nurse logrolls by:","Rolling the client onto their side while keeping their spine in alignment as a single unit,Turning the upper body first then the lower body,Asking the client to twist at the waist to assist,Having the client sit up first before turning".split(","),0,"Logrolling maintains spinal alignment by turning the entire body as one unit. Three nurses are ideal: one at the head, one at the shoulders/hips, one at the legs. A pillow between the knees maintains alignment. The client should not twist or flex the spine.","Musculoskeletal","Spinal Surgery","On count of three, all team members turn the client simultaneously — coordination prevents spinal misalignment.","logrolling,spinal fusion,body alignment,post-operative care".split(",")),
  q("RPN-CAT","Musculoskeletal",4,"A client with osteomyelitis has a PICC line for 6 weeks of IV antibiotic therapy. The nurse monitors the PICC insertion site for:","Signs of phlebitis and infection including redness and drainage and warmth,Only the dressing integrity,Blood return only,Temperature of the opposite arm".split(","),0,"PICC lines are long-term central venous access devices prone to infection and phlebitis. Daily site assessment for redness, swelling, warmth, drainage, and tenderness is essential. Dressing changes per protocol (usually every 7 days for transparent dressings) maintain sterility.","Musculoskeletal","Osteomyelitis","Osteomyelitis requires 4-6 weeks of IV antibiotics — the lengthy course increases central line infection risk.","osteomyelitis,PICC line,IV antibiotics,site assessment".split(",")),
  q("REX-PN","Musculoskeletal",3,"A client in skeletal traction should have weights:","Resting on the floor when not actively pulling,Hanging freely without touching the floor or bed at all times,Removed during sleep for comfort,Adjusted by the nurse based on comfort level".split(","),1,"Traction weights must hang freely at all times to maintain continuous pull. Weights resting on the floor eliminate the therapeutic effect. Only the provider orders weight adjustments. Countertraction is provided by the client's body weight and bed positioning.","Musculoskeletal","Traction Care","Never lift, remove, or adjust traction weights without a provider order — maintaining pull prevents bone displacement.","skeletal traction,weights,orthopedic care,nursing management".split(",")),
  q("REX-PN","Musculoskeletal",3,"A client with suspected fat embolism from a femur fracture has petechiae across the chest. The nurse should:","Apply oxygen and notify the provider immediately as fat embolism syndrome is an emergency,Document the finding and reassess in 8 hours,Apply a warm compress to the petechial area,Administer aspirin for the rash".split(","),0,"Fat embolism syndrome from long bone fractures presents 24-72 hours post-injury with the classic triad: respiratory distress, confusion, and petechial rash (chest, axillae, conjunctivae). Immediate oxygen therapy, intubation if needed, and supportive care are required.","Musculoskeletal","Fat Embolism Syndrome","Petechial rash on the chest in a client with a long bone fracture = fat embolism until proven otherwise.","fat embolism,femur fracture,petechiae,respiratory distress".split(",")),

  // === Renal (7 questions: 3 easy, 2 moderate, 2 difficult) ===
  q("REX-PN","Renal",1,"The nurse is collecting a 24-hour urine specimen. The correct procedure includes:","Saving the first voided specimen to start collection,Discarding the first voided specimen and collecting all subsequent urine for 24 hours,Collecting only the first morning void each day,Refrigerating the urine is unnecessary".split(","),1,"The 24-hour collection begins by discarding the first void (empties the bladder), then collecting ALL subsequent urine including the final void at exactly 24 hours. The specimen container is kept on ice or refrigerated to prevent bacterial growth.","Renal","Diagnostic Testing","If any specimen is accidentally discarded during the 24-hour period, the entire collection must be restarted.","24-hour urine,specimen collection,creatinine clearance,laboratory test".split(",")),
  q("REX-PN","Renal",1,"A client with a urinary tract infection should be encouraged to:","Decrease fluid intake to reduce urinary frequency,Increase fluid intake to at least 2-3 liters per day to flush bacteria,Take cranberry supplements as the sole treatment,Avoid urination as long as possible to reduce pain".split(","),1,"Increased fluid intake (2-3 L/day) dilutes urine and increases urinary frequency, which helps flush bacteria from the bladder. Cranberry products may help prevent UTIs but are not sufficient treatment alone. Antibiotics are the primary treatment.","Renal","Urinary Tract Infection","Emptying the bladder regularly prevents bacterial multiplication — urinate at least every 2-3 hours.","UTI,fluid intake,infection prevention,patient teaching".split(",")),
  q("REX-PN","Renal",1,"The nurse assesses a client with chronic kidney disease and notes asterixis and drowsiness. These findings suggest:","Adequate dialysis clearance,Uremic encephalopathy from accumulation of waste products,Normal neurological status for CKD,Medication side effects only".split(","),1,"Uremic encephalopathy results from BUN and toxin accumulation in advanced CKD. Symptoms include asterixis, drowsiness, confusion, seizures, and coma. Dialysis initiation or adjustment is needed to remove uremic toxins.","Renal","Chronic Kidney Disease","Asterixis in CKD = uremia. Also seen in hepatic encephalopathy (ammonia) and CO2 narcosis.","uremia,encephalopathy,CKD,dialysis".split(",")),
  q("REX-PN","Renal",3,"A client receiving hemodialysis through an AV fistula develops steal syndrome. The nurse assesses for:","Bruit and thrill in the fistula,Numbness, coolness, and pain in the hand distal to the fistula,Elevated blood pressure in the affected arm,Dark urine output".split(","),1,"Steal syndrome occurs when the AV fistula diverts too much arterial blood, depriving the distal extremity. Symptoms include numbness, tingling, coolness, pallor, and pain in the hand/fingers below the fistula site. Severe cases may require surgical revision.","Renal","Hemodialysis Complications","Steal syndrome: the fistula 'steals' blood from the hand. Compare hand temperature and color bilaterally.","AV fistula,steal syndrome,hemodialysis,vascular access".split(",")),
  q("RPN-CAT","Renal",4,"A client post-kidney transplant on immunosuppressive therapy develops a rising serum creatinine 3 months post-transplant. The nurse should suspect:","Normal post-transplant recovery,Acute graft rejection requiring urgent intervention,Dehydration as the sole cause,Chronic kidney disease recurrence".split(","),1,"Rising creatinine post-transplant is the hallmark of acute rejection. Other signs include fever, graft tenderness, decreased urine output, hypertension, and weight gain. Biopsy confirms diagnosis. Treatment includes high-dose IV corticosteroids and anti-rejection medications.","Renal","Kidney Transplant","Acute rejection occurs most commonly in the first 3-6 months post-transplant — any creatinine rise requires immediate evaluation.","kidney transplant,acute rejection,creatinine,immunosuppression".split(",")),
  q("REX-PN","Renal",3,"A client on peritoneal dialysis has outflow that is less than the infused volume. The nurse should first:","Increase the dwell time to 8 hours,Reposition the client from side to side to promote drainage,Remove the catheter and replace it,Increase the inflow volume".split(","),1,"Insufficient outflow in PD may be caused by catheter position, constipation, fibrin clots, or the omentum wrapping around the catheter. Repositioning the client is the first intervention. If unsuccessful, check for kinks, constipation, and notify the provider.","Renal","Peritoneal Dialysis","Constipation is a common cause of poor PD drainage — maintain bowel regularity.","peritoneal dialysis,outflow problems,repositioning,catheter".split(",")),
  q("REX-PN","Renal",3,"A client with acute glomerulonephritis has cola-colored urine and periorbital edema. Laboratory findings would show:","Normal BUN and creatinine,Elevated BUN and creatinine with hematuria and proteinuria,Decreased serum potassium,Elevated serum calcium".split(","),1,"Acute glomerulonephritis causes glomerular inflammation with impaired filtration. Cola-colored urine reflects hematuria, periorbital and facial edema results from sodium and water retention, and elevated BUN/creatinine indicate decreased GFR. Often occurs 1-3 weeks post-streptococcal infection.","Renal","Glomerulonephritis","Cola-colored urine + periorbital edema + recent strep infection = classic post-streptococcal glomerulonephritis presentation.","glomerulonephritis,hematuria,proteinuria,renal inflammation".split(",")),

  // === Maternal/Newborn (7 questions: 3 easy, 2 moderate, 2 difficult) ===
  q("REX-PN","Maternal/Newborn",1,"A postpartum client is breastfeeding her newborn. The nurse teaches that colostrum:","Has no nutritional value,Provides antibodies and promotes the passage of meconium,Should be discarded before mature milk comes in,Is identical to mature breast milk".split(","),1,"Colostrum (produced first 2-5 days) is rich in immunoglobulins (especially IgA), protein, fat-soluble vitamins, and has laxative properties that promote meconium passage. It provides passive immunity to the newborn and should never be discarded.","Maternal/Newborn","Breastfeeding","Colostrum's laxative effect helps clear bilirubin through meconium, reducing neonatal jaundice risk.","colostrum,breastfeeding,newborn nutrition,antibodies".split(",")),
  q("REX-PN","Maternal/Newborn",1,"The nurse assesses a newborn's Moro reflex by:","Gently tapping the infant's knee,Slightly lowering the infant's head causing the arms to extend symmetrically then adduct,Stroking the sole of the foot,Touching the infant's cheek".split(","),1,"The Moro (startle) reflex is elicited by a sudden change in position or loud noise. The infant symmetrically extends and abducts the arms, opens the hands, then adducts the arms in an embracing motion. Asymmetry suggests birth injury (Erb palsy, fracture).","Maternal/Newborn","Newborn Reflexes","Asymmetric Moro reflex suggests brachial plexus injury — compare both sides carefully.","Moro reflex,newborn assessment,primitive reflexes,Erb palsy".split(",")),
  q("REX-PN","Maternal/Newborn",1,"A pregnant client at 28 weeks gestation receives Rh immunoglobulin (RhoGAM). This is administered because the client is:","Rh positive carrying an Rh negative fetus,Rh negative to prevent sensitization to Rh positive fetal blood cells,Type O blood carrying a Type AB fetus,Anemic and needing immunoglobulin supplementation".split(","),1,"RhoGAM prevents Rh-negative mothers from developing antibodies against Rh-positive fetal red blood cells. Given at 28 weeks and within 72 hours after delivery of an Rh-positive infant. Also given after amniocentesis, miscarriage, or any potential fetal-maternal blood mixing.","Maternal/Newborn","Rh Incompatibility","RhoGAM is given to the Rh-NEGATIVE mother, not to the baby. It prevents sensitization, not treats it.","RhoGAM,Rh incompatibility,prenatal care,immunoglobulin".split(",")),
  q("RPN-CAT","Maternal/Newborn",4,"A laboring client with an epidural develops sudden hypotension. The nurse should first:","Elevate the head of bed to 90 degrees,Turn the client to the left lateral position and increase IV fluids,Administer oxytocin to speed delivery,Remove the epidural catheter".split(","),1,"Epidural anesthesia causes sympathetic blockade and vasodilation leading to hypotension. Left lateral positioning displaces the uterus off the inferior vena cava (aortocaval compression), improving venous return. IV fluid bolus restores intravascular volume. Ephedrine may be needed if BP doesn't improve.","Maternal/Newborn","Labor and Delivery","Left lateral position relieves aortocaval compression — this is the go-to position for maternal hypotension.","epidural,hypotension,left lateral,labor".split(",")),
  q("REX-PN","Maternal/Newborn",3,"A postpartum client 4 hours after vaginal delivery has a boggy uterus that is displaced to the right. The nurse should first:","Administer oxytocin immediately,Have the client empty her bladder then perform fundal massage,Notify the provider before any intervention,Apply ice to the abdomen".split(","),1,"A full bladder displaces the uterus to the right and prevents contraction, causing boggy uterus and increasing hemorrhage risk. Having the client void (or inserting a catheter) relieves the displacement, then fundal massage promotes uterine contraction.","Maternal/Newborn","Postpartum Care","Right-displaced boggy fundus = full bladder. Empty the bladder FIRST before performing fundal massage.","postpartum hemorrhage,boggy uterus,bladder distension,fundal massage".split(",")),
  q("REX-PN","Maternal/Newborn",3,"A newborn with physiologic jaundice is placed under phototherapy lights. The nurse should:","Cover the newborn's eyes with protective eye shields,Keep the newborn fully clothed during treatment,Limit breastfeeding to reduce bilirubin production,Turn off the lights for 30-minute breaks every hour".split(","),0,"Phototherapy converts unconjugated bilirubin in the skin to water-soluble isomers that can be excreted without liver conjugation. Eye shields prevent retinal damage. Maximum skin exposure (minimal clothing) increases effectiveness. Frequent feeding promotes bilirubin excretion through stool.","Maternal/Newborn","Neonatal Jaundice","Increase feeding frequency during phototherapy — more stools means more bilirubin elimination.","phototherapy,neonatal jaundice,bilirubin,eye protection".split(",")),
  q("RPN-CAT","Maternal/Newborn",4,"A pregnant client at 34 weeks presents with a placental abruption. The nurse assesses for which classic findings?","Painless bright red vaginal bleeding,Painful rigid abdomen with dark red vaginal bleeding and fetal distress,Absence of contractions with no bleeding,Clear vaginal discharge only".split(","),1,"Placental abruption presents with painful rigid (board-like) abdomen, dark red vaginal bleeding (may be concealed), uterine tenderness, and fetal distress. This differs from placenta previa which causes painless bright red bleeding. Emergency cesarean section may be indicated.","Maternal/Newborn","Obstetric Emergencies","Placenta previa = painless, bright red. Abruption = painful, dark red, rigid abdomen. This is a high-yield comparison.","placental abruption,vaginal bleeding,fetal distress,obstetric emergency".split(",")),

  // === Infection Control (7 questions: 3 easy, 2 moderate, 2 difficult) ===
  q("REX-PN","Infection Control",1,"Standard precautions apply to:","Only clients with known infections,All clients regardless of known or suspected infection status,Only clients in isolation rooms,Only clients with blood-borne diseases".split(","),1,"Standard precautions apply to ALL clients in ALL settings. They include hand hygiene, PPE based on anticipated exposure, respiratory hygiene, safe injection practices, and proper sharps disposal. This is the foundation of infection prevention.","Infection Control","Standard Precautions","Standard precautions assume every patient's blood and body fluids are potentially infectious.","standard precautions,infection prevention,hand hygiene,universal".split(",")),
  q("REX-PN","Infection Control",1,"A client with C. difficile infection requires which type of hand hygiene?","Alcohol-based hand rub,Soap and water handwashing for at least 20 seconds,Quick rinse under running water,Hand sanitizer gel only".split(","),1,"C. difficile forms spores that are not killed by alcohol-based hand sanitizers. Soap and water physically removes spores through mechanical action. Contact precautions (gown and gloves) are also required, along with bleach-based environmental cleaning.","Infection Control","C. difficile Precautions","Alcohol does NOT kill C. diff spores — soap and water is mandatory. This is an exam favorite.","C. difficile,hand hygiene,spores,contact precautions".split(",")),
  q("REX-PN","Infection Control",1,"The nurse is preparing to enter an airborne isolation room for a client with active tuberculosis. Required PPE includes:","Surgical mask,Fitted N95 respirator,Gown and gloves only,No special PPE needed".split(","),1,"Airborne precautions for TB require an N95 respirator that has been fit-tested for the individual nurse. The client must be in a negative-pressure room. A surgical mask is placed on the client during transport outside the room.","Infection Control","Airborne Precautions","N95 must be fit-tested annually. A surgical mask is NOT adequate for airborne precautions.","tuberculosis,N95 respirator,airborne precautions,fit testing".split(",")),
  q("REX-PN","Infection Control",3,"A nurse sustains a needlestick injury from a client with unknown HIV status. The nurse should:","Wait for the client's HIV test results before taking action,Immediately wash the site and report the exposure for post-exposure prophylaxis evaluation within 2 hours,Apply a bandage and continue working,Report the exposure at the end of the shift".split(","),1,"Immediate wound cleansing (soap and water for skin, flushing for mucous membranes) followed by reporting to occupational health within 2 hours is critical. PEP (antiretroviral medications) is most effective when started within 72 hours (ideally within 2 hours). Source patient testing is also initiated.","Infection Control","Needlestick Protocol","PEP is most effective within 2 hours of exposure — every hour of delay reduces effectiveness.","needlestick,post-exposure prophylaxis,HIV,occupational safety".split(",")),
  q("RPN-CAT","Infection Control",4,"A client with meningococcal meningitis requires which isolation precaution?","Contact precautions only,Droplet precautions until 24 hours after effective antibiotic therapy,Airborne precautions indefinitely,Standard precautions only".split(","),1,"Neisseria meningitidis is transmitted via respiratory droplets. Droplet precautions (surgical mask within 3-6 feet) are required until 24 hours after effective antibiotic therapy. Close contacts should receive chemoprophylaxis (rifampin, ciprofloxacin, or ceftriaxone).","Infection Control","Meningococcal Disease","Close contacts of meningococcal meningitis need chemoprophylaxis — rifampin or ciprofloxacin within 24 hours.","meningococcal meningitis,droplet precautions,chemoprophylaxis,isolation".split(",")),
  q("REX-PN","Infection Control",3,"The nurse is caring for a client with vancomycin-resistant enterococcus (VRE). The most effective measure to prevent transmission is:","Administering prophylactic antibiotics to roommates,Strict hand hygiene and contact precautions with dedicated equipment,Airborne isolation in a negative-pressure room,Restricting visitors completely".split(","),1,"VRE requires contact precautions: gown and gloves upon room entry, dedicated equipment (stethoscope, BP cuff), and meticulous hand hygiene with soap and water. VRE survives on surfaces for weeks, requiring thorough environmental cleaning with appropriate disinfectants.","Infection Control","Multidrug-Resistant Organisms","VRE can survive on environmental surfaces for weeks — dedicated equipment prevents cross-contamination.","VRE,contact precautions,hand hygiene,dedicated equipment".split(",")),

  // === Hematological (7 questions: 2 easy, 3 moderate, 2 difficult) ===
  q("REX-PN","Hematological",1,"A client with a platelet count of 20,000/mm3 should be placed on which precautions?","No special precautions needed,Bleeding precautions including soft toothbrush and electric razor and avoiding IM injections,Contact isolation,Fall prevention only".split(","),1,"Severe thrombocytopenia (< 50,000) increases spontaneous bleeding risk. Precautions include soft toothbrush, electric razor, avoiding IM injections and rectal temperatures, applying pressure to venipuncture sites, and monitoring for internal bleeding signs.","Hematological","Thrombocytopenia","Platelet count < 10,000: risk of spontaneous intracranial hemorrhage — extreme caution required.","thrombocytopenia,bleeding precautions,platelet count,safety".split(",")),
  q("REX-PN","Hematological",1,"A client with iron-deficiency anemia should take oral iron supplements:","With milk for better tolerance,On an empty stomach with orange juice to enhance absorption,With calcium supplements,At bedtime with antacids".split(","),1,"Vitamin C (ascorbic acid in orange juice) enhances iron absorption by converting ferric iron to the more absorbable ferrous form. Empty stomach maximizes absorption. Milk, calcium, antacids, and tannins (tea) inhibit absorption.","Hematological","Iron-Deficiency Anemia","Black tarry stools are a normal side effect of iron supplements — not a sign of GI bleeding in this context.","iron supplements,vitamin C,anemia,medication administration".split(",")),
  q("REX-PN","Hematological",3,"A client with disseminated intravascular coagulation presents with simultaneous bleeding and clotting. The nurse monitors for:","Elevated platelet count,Decreased fibrinogen and elevated D-dimer and prolonged PT/aPTT,Normal coagulation studies,Elevated hemoglobin".split(","),1,"DIC consumes clotting factors and platelets causing both thrombosis and hemorrhage simultaneously. Labs show decreased fibrinogen (consumed), elevated D-dimer (fibrin degradation), prolonged PT/aPTT, and thrombocytopenia. Treatment targets the underlying cause.","Hematological","DIC","DIC: think 'Death Is Coming' — it is a secondary condition. Treatment depends on treating the underlying cause.","DIC,coagulation,fibrinogen,D-dimer".split(",")),
  q("RPN-CAT","Hematological",4,"A client receiving a blood transfusion develops fever, chills, and flank pain 15 minutes into the transfusion. The nurse suspects a hemolytic reaction and should:","Slow the rate and add a filter,Stop the transfusion immediately and infuse NS through new tubing and send blood samples to the lab,Administer acetaminophen and continue,Increase the rate to complete the transfusion quickly".split(","),1,"Acute hemolytic transfusion reaction is life-threatening (ABO incompatibility). Stop transfusion immediately, disconnect blood tubing, maintain IV with NS through new tubing, send remaining blood and client samples to lab, monitor VS, and support renal function.","Hematological","Transfusion Reactions","Use NEW IV tubing for the NS — old tubing still contains incompatible blood.","hemolytic reaction,blood transfusion,ABO incompatibility,emergency".split(",")),
  q("REX-PN","Hematological",3,"A client with sickle cell disease in vasoocclusive crisis requires which priority nursing interventions?","Cold applications and fluid restriction,Aggressive IV hydration and pain management and supplemental oxygen,Blood transfusion as the sole treatment,Activity promotion to prevent joint stiffness".split(","),1,"Vasoocclusive crisis management priorities: aggressive IV hydration (dilutes sickled cells and maintains renal perfusion), analgesics including opioids for severe pain, supplemental oxygen (prevents further sickling), and rest. Avoid cold (causes vasoconstriction and worsens crisis).","Hematological","Sickle Cell Disease","AVOID cold and dehydration in sickle cell — both trigger sickling. Hydrate aggressively.","sickle cell crisis,hydration,pain management,oxygenation".split(",")),
  q("REX-PN","Hematological",3,"A client taking warfarin develops an INR of 8.5 with epistaxis. The nurse anticipates:","Continuing warfarin at the current dose,Administering vitamin K and holding warfarin,Administering aspirin for the nosebleed,Increasing the warfarin dose".split(","),1,"INR > 5 with bleeding requires vitamin K administration (IV for serious bleeding, oral for minor bleeding) and warfarin discontinuation. Severe or life-threatening bleeding may require fresh frozen plasma or prothrombin complex concentrate for immediate reversal.","Hematological","Anticoagulation Reversal","IV vitamin K works within 6-12 hours. FFP or PCC provides immediate reversal for life-threatening bleeding.","warfarin,vitamin K,INR reversal,bleeding".split(",")),
  q("REX-PN","Hematological",3,"A client receiving heparin therapy develops heparin-induced thrombocytopenia (HIT). The nurse should:","Continue heparin and monitor platelets,Discontinue all heparin products immediately including heparin flushes and start an alternative anticoagulant,Switch to low-molecular-weight heparin,Administer platelet transfusions".split(","),1,"HIT is an immune-mediated reaction causing platelet-activating antibodies that paradoxically cause thrombosis despite low platelets. ALL heparin (including flushes and LMWH) must be stopped. Direct thrombin inhibitors (argatroban, bivalirudin) are alternative anticoagulants. Platelet transfusions can worsen thrombosis.","Hematological","HIT","HIT causes thrombosis despite low platelets — never give platelet transfusions as they fuel clot formation.","HIT,heparin,thrombocytopenia,alternative anticoagulant".split(",")),

  // === Integumentary (5 questions: 2 easy, 1 moderate, 2 difficult) ===
  q("REX-PN","Integumentary",1,"The nurse assesses a client's wound and notes red granulation tissue at the base. This indicates:","Wound infection requiring antibiotics,Healthy wound healing with new capillary formation,Necrotic tissue requiring debridement,An allergic reaction to wound dressing".split(","),1,"Red, beefy granulation tissue indicates healthy wound healing with new blood vessel formation (angiogenesis) and collagen deposition. Protect this tissue from trauma during dressing changes. Black tissue indicates necrosis, yellow indicates slough.","Integumentary","Wound Assessment","Red = healthy granulation, Yellow = slough, Black = necrotic eschar. Color guides treatment decisions.","wound healing,granulation tissue,wound assessment,tissue types".split(",")),
  q("REX-PN","Integumentary",1,"A client at risk for pressure injuries should be repositioned at minimum every:","4 hours,2 hours when in bed,8 hours,Once per nursing shift".split(","),1,"Repositioning every 2 hours in bed (and every 1 hour in a chair) relieves sustained pressure that causes tissue ischemia and pressure injury development. Use the 30-degree lateral tilt and avoid positioning directly on trochanters.","Integumentary","Pressure Injury Prevention","A 30-degree lateral tilt redistributes pressure better than a full side-lying position.","pressure injury,repositioning,prevention,skin care".split(",")),
  q("REX-PN","Integumentary",3,"A client with a full-thickness burn over 40% TBSA requires fluid resuscitation using the Parkland formula. The nurse calculates:","4 mL x body weight (kg) x percentage TBSA burned with half given in the first 8 hours from the time of injury,2 mL x body weight x TBSA burned,Total fluids over 24 hours divided equally,10 mL x TBSA burned regardless of weight".split(","),0,"The Parkland formula: 4 mL x kg x %TBSA burned of lactated Ringer's over 24 hours. Half is given in the first 8 hours from the TIME OF INJURY (not from hospital arrival). The remaining half is given over the next 16 hours. Titrate to urine output 0.5-1 mL/kg/hr.","Integumentary","Burn Management","The 8-hour calculation starts from the TIME OF BURN, not time of hospital arrival — this catches many nurses off guard.","Parkland formula,burn,fluid resuscitation,TBSA".split(",")),
  q("RPN-CAT","Integumentary",4,"A client with a deep partial-thickness burn develops a circumferential burn on the right forearm with absent radial pulse. The nurse should prepare for:","Applying a compression bandage,Escharotomy to relieve compartment pressure,Skin grafting immediately,Wound debridement only".split(","),1,"Circumferential burns create a tight, inelastic eschar that constricts as tissue swells, compromising circulation (absent pulses) and potentially causing compartment syndrome. Escharotomy (surgical incision through the eschar) releases pressure and restores blood flow.","Integumentary","Burn Complications","Absent pulses in a circumferential burn = escharotomy urgently needed. This is a time-critical intervention.","escharotomy,circumferential burn,compartment syndrome,vascular compromise".split(",")),
  q("REX-PN","Integumentary",3,"A client with a negative-pressure wound therapy (wound VAC) system has the alarm sounding. The nurse should first:","Remove the dressing entirely,Check all tubing connections and dressing seal for air leaks,Turn off the device permanently,Cover the wound with dry gauze".split(","),1,"Wound VAC alarms typically indicate loss of seal. The nurse checks for air leaks at tubing connections and dressing edges. Resealing with additional adhesive drape over leak sites usually resolves the issue. Ensure tubing is not kinked or clogged and the canister is not full.","Integumentary","Wound VAC Therapy","Most wound VAC alarms are caused by dressing seal breaks — listen for the hissing sound to find the leak.","wound VAC,negative pressure,wound therapy,troubleshooting".split(",")),

  // === Immunological (5 questions: 2 easy, 1 moderate, 2 difficult) ===
  q("REX-PN","Immunological",1,"A client with seasonal allergies asks about antihistamine side effects. The nurse explains that first-generation antihistamines commonly cause:","Insomnia and hyperactivity,Drowsiness and dry mouth,Weight loss,Diarrhea".split(","),1,"First-generation antihistamines (diphenhydramine, chlorpheniramine) cross the blood-brain barrier causing sedation and have anticholinergic effects causing dry mouth, urinary retention, and constipation. Second-generation (cetirizine, loratadine) are less sedating.","Immunological","Allergy Management","Diphenhydramine should be avoided in elderly clients due to increased anticholinergic side effects and fall risk.","antihistamines,allergies,side effects,patient education".split(",")),
  q("REX-PN","Immunological",1,"The nurse teaches a client about the importance of completing the hepatitis B vaccine series. How many doses are required?","One dose for lifetime immunity,Three doses given at 0 and 1 and 6 months,Two doses given 1 month apart,Five doses over 2 years".split(","),1,"The hepatitis B vaccine series requires 3 doses at 0, 1, and 6 months for full immunity. Post-vaccination testing for anti-HBs is recommended for healthcare workers and high-risk individuals. Immunity is considered lifelong in immunocompetent individuals.","Immunological","Immunization","Healthcare workers should have anti-HBs titer checked 1-2 months after completing the 3-dose series.","hepatitis B vaccine,immunization schedule,3-dose series,antibody testing".split(",")),
  q("REX-PN","Immunological",3,"A client with severe combined immunodeficiency disease requires which critical precaution?","Standard precautions only,Strict protective (reverse) isolation with HEPA-filtered air,Droplet precautions,No special precautions".split(","),1,"SCID results in absence of both T-cell and B-cell immunity, making the client extremely susceptible to all infections. Protective isolation with HEPA-filtered air, strict hand hygiene, and avoiding live vaccines are essential. Bone marrow transplant is the definitive treatment.","Immunological","Immunodeficiency","SCID is a pediatric emergency — untreated children rarely survive past the first year.","SCID,immunodeficiency,protective isolation,HEPA filtration".split(",")),
  q("RPN-CAT","Immunological",4,"A client receiving rituximab for rheumatoid arthritis develops progressive multifocal leukoencephalopathy. The nurse understands this is caused by:","Bacterial meningitis from immunosuppression,JC virus reactivation due to immunosuppression,Direct neurotoxicity of the medication,Autoimmune CNS inflammation".split(","),1,"PML is a devastating opportunistic infection caused by JC virus reactivation in immunosuppressed patients. Rituximab depletes B cells, reducing immune surveillance. PML causes progressive neurological deficits including cognitive decline, weakness, vision loss, and is often fatal.","Immunological","Biologic Therapy Complications","PML is an FDA black box warning for rituximab, natalizumab, and other immunosuppressive biologics.","PML,rituximab,JC virus,immunosuppression".split(",")),
  q("REX-PN","Immunological",3,"A client with anaphylaxis has been treated with epinephrine. The nurse should continue to monitor for:","Full recovery within 5 minutes,Biphasic reaction occurring 4-12 hours after initial resolution,No further monitoring needed after epinephrine,Only skin rash recurrence".split(","),1,"Biphasic anaphylaxis occurs in up to 20% of cases, with symptom recurrence 4-12 hours (sometimes up to 72 hours) after initial resolution without re-exposure. Extended observation (minimum 4-6 hours, longer for severe reactions) and prescribing an epinephrine auto-injector are recommended.","Immunological","Anaphylaxis Management","Prescribe 2 epinephrine auto-injectors at discharge — up to 30% of reactions require a second dose.","anaphylaxis,biphasic reaction,epinephrine,monitoring".split(",")),

  // === Reproductive (5 questions: 2 easy, 1 moderate, 2 difficult) ===
  q("REX-PN","Reproductive",1,"A female client asks about breast self-examination timing. The nurse instructs her to perform BSE:","On the first day of each month regardless of menses,7-10 days after the onset of menstruation when breast tissue is least tender,Only when a lump is felt,Before each menstrual period".split(","),1,"BSE is best performed 7-10 days after menses onset when hormonal breast swelling and tenderness have subsided, making it easier to detect changes. Post-menopausal women should select a consistent day each month.","Reproductive","Breast Health","Post-menopausal women: pick the same day each month (like the 1st) for consistency in BSE.","breast self-examination,BSE timing,breast health,screening".split(",")),
  q("REX-PN","Reproductive",1,"The nurse teaches a male client about testicular self-examination. The exam should be performed:","After a warm shower when the scrotal skin is relaxed,Before exercise when muscles are tight,Only at annual physician visits,In cold temperatures for better palpation".split(","),0,"Warm water relaxes the scrotal skin, making it easier to palpate the testes. Each testis should be examined separately by rolling it between the thumbs and fingers, feeling for lumps, swelling, or changes. The epididymis is a normal posterior structure.","Reproductive","Testicular Health","Testicular cancer peaks in men ages 15-35 — this is the demographic that benefits most from TSE education.","testicular self-examination,TSE,testicular cancer,male health".split(",")),
  q("REX-PN","Reproductive",3,"A client with endometriosis is prescribed leuprolide (Lupron). The nurse explains that this medication works by:","Stimulating estrogen production,Creating a temporary menopausal state by suppressing ovarian hormone production,Directly destroying endometrial implants,Increasing progesterone levels".split(","),1,"Leuprolide is a GnRH agonist that initially stimulates then suppresses pituitary gonadotropin release, creating a hypoestrogenic state (medical menopause). This shrinks endometrial implants and reduces pain. Side effects include hot flashes, vaginal dryness, and bone density loss.","Reproductive","Endometriosis","Leuprolide causes an initial flare of symptoms before suppression — educate clients to expect temporary worsening.","endometriosis,leuprolide,GnRH agonist,hormone suppression".split(",")),
  q("RPN-CAT","Reproductive",4,"A client with ovarian hyperstimulation syndrome from fertility treatment presents with abdominal distension and dyspnea. The nurse should monitor for:","Hypervolemia and hypertension,Third-space fluid shift causing hemoconcentration and thromboembolism risk,Hypoglycemia only,Bone marrow suppression".split(","),1,"OHSS causes massive fluid shift from intravascular to third spaces (ascites, pleural effusion) leading to hemoconcentration, hypercoagulability, electrolyte imbalances, and potential renal failure. Severe cases require hospitalization with fluid management and thromboprophylaxis.","Reproductive","Fertility Treatment Complications","OHSS is counterintuitive: the client has massive fluid accumulation but is intravascularly depleted and at clot risk.","OHSS,fertility treatment,hemoconcentration,thromboembolism".split(",")),
  q("REX-PN","Reproductive",3,"A client with cervical cancer is scheduled for brachytherapy. The nurse implements which radiation safety precaution?","No special precautions since internal radiation is safe for staff,Limit time near the client and maintain distance and use shielding,Only the physician needs radiation precautions,Visitors can stay unlimited time at the bedside".split(","),1,"Brachytherapy (internal radiation) requires ALARA and time-distance-shielding principles. Limit time in the room, maximize distance from the source, use portable lead shields, assign non-pregnant nurses, and restrict visitors (no pregnant women or children under 18).","Reproductive","Radiation Therapy","Time, Distance, Shielding. No pregnant nurses. No children visiting. Collect all linens — a dislodged source must never be picked up by hand.","brachytherapy,radiation safety,cervical cancer,ALARA".split(",")),

  // === Emergency (5 questions: 2 easy, 1 moderate, 2 difficult) ===
  q("REX-PN","Emergency",1,"A client is choking and cannot speak or cough. The nurse should perform:","Back blows only,Abdominal thrusts (Heimlich maneuver) until the object is dislodged or the person becomes unconscious,Finger sweeps before assessing the airway,Mouth-to-mouth breathing immediately".split(","),1,"For a conscious choking adult who cannot speak, cough, or breathe, perform abdominal thrusts (Heimlich maneuver) from behind. If the person becomes unconscious, lower them to the ground and begin CPR. Blind finger sweeps are no longer recommended.","Emergency","Choking/Airway Obstruction","For pregnant or obese clients who cannot receive abdominal thrusts, use chest thrusts instead.","choking,Heimlich maneuver,airway obstruction,first aid".split(",")),
  q("REX-PN","Emergency",1,"When a client arrives in the emergency department with a suspected stroke, the nurse prioritizes:","Obtaining a detailed health history over 30 minutes,Rapid neurological assessment and CT scan to differentiate ischemic from hemorrhagic stroke,Starting anticoagulation therapy immediately,Administering morphine for headache".split(","),1,"Time is critical in stroke management. CT scan differentiates ischemic (eligible for tPA within 4.5 hours) from hemorrhagic stroke (tPA is contraindicated). The National Institutes of Health Stroke Scale (NIHSS) quantifies deficit severity. Document the last known well time.","Emergency","Stroke","tPA window: within 4.5 hours of symptom onset. CT must rule out hemorrhage BEFORE tPA administration.","stroke,CT scan,tPA,time-critical".split(",")),
  q("REX-PN","Emergency",3,"A client with suspected cervical spine injury after a diving accident is found face-down in the water. The nurse should:","Roll the client to supine using logroll technique while maintaining cervical spine alignment,Pull the client out by the arms,Lift the client's head out of the water first,Wait for EMS without entering the water".split(","),0,"In water rescue with suspected spinal injury, the client is logrolled supine while maintaining in-line cervical stabilization, then floated to a backboard. C-spine must be immobilized throughout rescue. Movement without stabilization risks permanent spinal cord damage.","Emergency","Spinal Injury Rescue","In-water cervical stabilization: use the head-splint technique — trap the head between your arms while turning.","cervical spine,water rescue,logroll,immobilization".split(",")),
  q("RPN-CAT","Emergency",4,"A client with a crush injury has been trapped under debris for 4 hours. Upon rescue and release, the nurse should immediately monitor for:","Hypothermia only,Crush syndrome with hyperkalemia causing fatal cardiac dysrhythmias,Localized wound infection,Dehydration and sunburn".split(","),1,"Crush syndrome occurs when prolonged compression causes rhabdomyolysis. Upon release, massive amounts of myoglobin, potassium, and phosphorus flood the circulation, causing hyperkalemia (cardiac arrest risk), metabolic acidosis, and acute renal failure. Pre-hospital IV fluids and cardiac monitoring are essential.","Emergency","Crush Injury","Start IV fluids BEFORE extrication if possible — aggressive hydration prevents renal failure from myoglobin.","crush syndrome,hyperkalemia,rhabdomyolysis,rescue".split(",")),
  q("REX-PN","Emergency",3,"A client with severe burns has a carboxyhemoglobin level of 35%. The nurse should:","Remove the client from the CO source and administer 100% oxygen via non-rebreather mask,Administer oxygen at 2 L/min by nasal cannula,Provide room air ventilation,Wait for arterial blood gas results before treating".split(","),0,"Carbon monoxide has 200x greater affinity for hemoglobin than oxygen. High-flow 100% oxygen displaces CO from hemoglobin. COHb > 25% is severe poisoning with confusion, loss of consciousness, and cardiac ischemia risk. Hyperbaric oxygen may be needed for levels > 25%.","Emergency","Carbon Monoxide Poisoning","Pulse oximetry reads falsely normal in CO poisoning — it cannot distinguish COHb from oxyhemoglobin.","carbon monoxide,carboxyhemoglobin,100% oxygen,burn".split(",")),

  // === Oncology (5 questions: 2 easy, 1 moderate, 2 difficult) ===
  q("REX-PN","Oncology",1,"A client receiving chemotherapy asks why blood counts are monitored frequently. The nurse explains that chemotherapy:","Only targets cancer cells without affecting healthy cells,Affects rapidly dividing cells including bone marrow leading to myelosuppression,Only affects red blood cells,Has no effect on the immune system".split(","),1,"Chemotherapy drugs target rapidly dividing cells, which includes cancer cells and healthy cells with high mitotic rates: bone marrow (causing anemia, neutropenia, thrombocytopenia), GI mucosa (nausea, mucositis), and hair follicles (alopecia).","Oncology","Chemotherapy Side Effects","The nadir (lowest blood count point) typically occurs 7-14 days after chemotherapy — this is the highest infection risk period.","chemotherapy,myelosuppression,blood counts,nadir".split(",")),
  q("REX-PN","Oncology",1,"A client with cancer reports significant weight loss and muscle wasting despite adequate caloric intake. The nurse recognizes this as:","Normal weight fluctuation,Cancer cachexia,Medication side effect only,Psychological eating disorder".split(","),1,"Cancer cachexia is a multifactorial syndrome characterized by ongoing loss of skeletal muscle mass (with or without fat loss) that cannot be fully reversed by conventional nutritional support. It is driven by tumor-derived cytokines altering metabolism and affects 50-80% of advanced cancer patients.","Oncology","Cancer Cachexia","Cachexia involves metabolic changes — simply increasing calories does not reverse the muscle wasting.","cachexia,weight loss,muscle wasting,oncology nutrition".split(",")),
  q("REX-PN","Oncology",3,"A client receiving cisplatin chemotherapy has a serum creatinine rising from baseline. The nurse knows the priority intervention is:","Discontinuing all fluids,Aggressive IV hydration before and during cisplatin infusion to protect renal function,Administering dexrazoxane,Reducing the cisplatin dose without hydration".split(","),1,"Cisplatin is highly nephrotoxic. Aggressive pre-hydration with normal saline (1-2 L before treatment) promotes renal perfusion and dilutes cisplatin in the renal tubules. Monitoring urine output and serum creatinine is essential. Amifostine may be used as a cytoprotectant.","Oncology","Chemotherapy-Induced Nephrotoxicity","A urine output target of 100-150 mL/hour during cisplatin infusion reduces renal tubular damage.","cisplatin,nephrotoxicity,hydration,renal protection".split(",")),
  q("RPN-CAT","Oncology",4,"A client with small cell lung cancer develops syndrome of inappropriate antidiuretic hormone secretion. The nurse monitors for:","Hypernatremia and dehydration,Hyponatremia with concentrated urine and dilutional symptoms,Hyperkalemia,Metabolic acidosis".split(","),1,"SIADH from ectopic ADH secretion by small cell lung cancer causes water retention, dilutional hyponatremia (< 135 mEq/L), concentrated urine despite dilute serum, and symptoms including headache, confusion, nausea, and seizures. Treatment includes fluid restriction and possibly hypertonic saline.","Oncology","Paraneoplastic Syndromes","SIADH = low serum sodium + high urine sodium + concentrated urine. Fluid restriction is the primary treatment.","SIADH,hyponatremia,paraneoplastic,small cell lung cancer".split(",")),
  q("REX-PN","Oncology",3,"A client undergoing radiation therapy to the chest develops esophagitis. The nurse should recommend:","Spicy foods to stimulate appetite,Soft bland cool foods and topical anesthetic rinses before meals,Hot beverages to soothe the throat,Acidic juices for vitamin C intake".split(","),1,"Radiation esophagitis causes painful swallowing (odynophagia) and dysphagia. Soft, bland, cool or room-temperature foods reduce irritation. Topical anesthetics (viscous lidocaine) before meals ease pain. Avoid hot, spicy, acidic, and rough-textured foods. Liquid nutritional supplements maintain caloric intake.","Oncology","Radiation Side Effects","Viscous lidocaine swish-and-swallow before meals allows adequate oral intake despite esophageal pain.","radiation esophagitis,dysphagia,bland diet,pain management".split(",")),

  // === Perioperative (5 questions: 2 easy, 1 moderate, 2 difficult) ===
  q("REX-PN","Perioperative",1,"The nurse verifies informed consent before surgery. Which statement indicates the client understands the procedure?","The doctor said I need it so I signed,I understand the risks and benefits of the procedure and the alternatives and the consequences of not having it,My family told me to sign the consent,I just want to get it over with".split(","),1,"Informed consent requires the client to demonstrate understanding of the procedure, expected benefits, risks, alternatives, and consequences of refusal. It is the provider's responsibility to explain; the nurse witnesses the signature and ensures the client is informed.","Perioperative","Informed Consent","The nurse's role is to witness and verify understanding — not to explain the procedure to the client.","informed consent,surgical safety,patient rights,documentation".split(",")),
  q("REX-PN","Perioperative",1,"The nurse is conducting a preoperative assessment. Which finding should be reported to the surgeon before surgery?","The client took aspirin yesterday,The client ate a light breakfast 2 hours ago,The client's hemoglobin is 14 g/dL,The client's blood pressure is 120/78".split(","),1,"NPO guidelines (typically 6-8 hours for solids, 2 hours for clear liquids) reduce aspiration risk during anesthesia. Eating 2 hours before surgery may require postponement. The anesthesiologist must be informed to determine if the procedure can safely proceed.","Perioperative","Preoperative Assessment","Recent aspirin use should also be reported — it impairs platelet function and increases surgical bleeding risk.","preoperative assessment,NPO,aspiration risk,surgical safety".split(",")),
  q("REX-PN","Perioperative",3,"A client in the PACU has a respiratory rate of 6, SpO2 of 88%, and is difficult to arouse. The nurse suspects:","Normal post-anesthesia sedation,Opioid-induced respiratory depression requiring naloxone,Hypothermia,Anxiety".split(","),1,"Opioid-induced respiratory depression in the PACU presents with decreased respiratory rate (< 10), decreased SpO2, sedation, and pinpoint pupils. Naloxone (Narcan) reverses opioid effects. Titrate in small doses (0.04-0.4 mg IV) to avoid complete analgesia reversal and withdrawal symptoms.","Perioperative","Post-Anesthesia Complications","Titrate naloxone in small increments — too much too fast reverses all pain relief and can cause severe pain.","PACU,respiratory depression,naloxone,opioid reversal".split(",")),
  q("RPN-CAT","Perioperative",4,"A surgical client on postoperative day 2 develops a temperature of 38.8°C. The most likely cause is:","Wound infection (too early for surgical site infection),Atelectasis from inadequate lung expansion,Transfusion reaction,Drug fever from anesthesia".split(","),1,"The mnemonic for postoperative fever timing — Wind (atelectasis, POD 1-2), Water (UTI, POD 3-5), Wound (SSI, POD 5-7), Walking (DVT/PE, POD 5+), Wonder drugs (drug fever, any time). Day 2 fever is most commonly from atelectasis due to shallow breathing and immobility.","Perioperative","Postoperative Fever","Wind, Water, Wound, Walking, Wonder drugs — the 5 W's of postoperative fever by timing.","postoperative fever,atelectasis,5 W's,surgical complications".split(",")),
  q("REX-PN","Perioperative",3,"A client returns from surgery with an epidural catheter for pain management. The nurse assesses for which complication?","Hyperglycemia,Hypotension from sympathetic blockade and urinary retention,Tachycardia and hypertension,Diarrhea".split(","),1,"Epidural analgesia blocks sympathetic nerves causing vasodilation and hypotension. It also blocks parasympathetic bladder innervation causing urinary retention. Additional monitoring includes assessing dermatome level, motor function (leg weakness), and respiratory status for catheter migration.","Perioperative","Epidural Analgesia","Test dermatome level with ice — if sensory block rises above T4, respiratory compromise is possible.","epidural,hypotension,urinary retention,post-surgical pain".split(",")),

  // === Safety (5 questions: 2 easy, 1 moderate, 2 difficult) ===
  q("REX-PN","Safety",1,"The nurse identifies a client at high risk for falls. Which intervention should be implemented first?","Apply wrist restraints,Ensure the call light is within reach and the bed is in the lowest position,Keep the room dark to promote sleep,Restrict all ambulation".split(","),1,"Fall prevention begins with simple environmental modifications: bed in lowest position, call light within reach, non-skid footwear, clear pathways, adequate lighting, and toileting schedule. Restraints are last resort and can increase fall injury risk.","Safety","Fall Prevention","The call light within reach is the single most important fall prevention measure — never leave a patient without it.","fall prevention,patient safety,environmental safety,call light".split(",")),
  q("REX-PN","Safety",1,"When administering medications, the nurse discovers a medication error was made. The first action is to:","Notify the pharmacy before assessing the client,Assess the client for adverse effects and ensure client safety,Document the error and continue with other medications,Wait to see if symptoms develop before reporting".split(","),1,"Client safety is always the priority. Assess for adverse effects, provide any necessary interventions, notify the provider and charge nurse, complete an incident report, and document per facility policy. Never alter the medical record to cover an error.","Safety","Medication Error Management","Incident reports are NOT placed in the medical record — they are quality improvement documents.","medication error,patient safety,incident report,nursing responsibility".split(",")),
  q("REX-PN","Safety",3,"A nurse is caring for a client receiving a PCA pump for pain management. Which finding requires the nurse to intervene?","Pain rated at 3/10,A family member pressing the PCA button while the client sleeps,Client requesting the PCA pump be brought closer,Pain rated at 5/10 before activity".split(","),1,"Only the client should press the PCA button — this is a built-in safety mechanism. If the client is too sedated to press the button, they are too sedated for additional opioids. Family members pressing the button (PCA by proxy) can cause life-threatening oversedation and respiratory depression.","Safety","PCA Safety","PCA by proxy (family pressing the button) is a sentinel event risk — only the patient activates the pump.","PCA pump,opioid safety,patient-controlled analgesia,oversedation".split(",")),
  q("RPN-CAT","Safety",4,"During a code blue, the nurse discovers the client's advance directive specifies DNR. The nurse should:","Continue resuscitation efforts,Communicate the DNR status to the code team leader to stop resuscitation,Ignore the advance directive during an emergency,Ask the family to decide during the code".split(","),1,"A valid DNR order must be honored. The nurse immediately communicates the DNR status to the code team leader who determines the appropriate response. If there is any question about the validity of the order, resuscitation continues until the situation is clarified by the attending physician.","Safety","Advance Directives","DNR means Do Not Resuscitate — it does not mean Do Not Treat. The client still receives all other appropriate care.","DNR,advance directive,code blue,ethical practice".split(",")),
  q("REX-PN","Safety",3,"A nurse discovers a suspicious powder in a client's personal belongings during admission. The correct action is to:","Taste the substance to identify it,Avoid touching the substance and secure the area and notify security and follow facility policy,Flush the substance down the toilet,Return the substance to the client's family".split(","),1,"Unknown substances should never be touched, tasted, or disposed of. The nurse secures the area, avoids contamination, and notifies security and the charge nurse per facility policy. The substance may need to be analyzed. Client safety and legal considerations guide the response.","Safety","Unknown Substance Protocol","Chain of custody must be maintained for any suspicious substance — it may become evidence.","unknown substance,safety protocol,security,chain of custody".split(",")),

  // === Geriatrics (3 questions: 1 easy, 1 moderate, 1 difficult) ===
  q("REX-PN","Geriatrics",1,"The nurse assesses an elderly client and notes decreased skin turgor on the forearm. The nurse should:","Document poor hydration based on this finding alone,Assess skin turgor on the forehead or sternum as these are more reliable indicators in elderly clients,Start IV fluids immediately,Report dehydration to the provider".split(","),1,"Elderly clients have decreased skin elasticity making arm and hand turgor unreliable. The forehead and sternum maintain better turgor assessment accuracy. Other dehydration indicators in elderly include concentrated urine, orthostatic hypotension, confusion, and dry mucous membranes.","Geriatrics","Assessment Modifications","The forehead and sternum are the most reliable turgor assessment sites in elderly clients — arms are unreliable.","elderly assessment,skin turgor,dehydration,geriatric nursing".split(",")),
  q("REX-PN","Geriatrics",3,"An elderly client on multiple medications develops confusion. The nurse should first consider:","Normal aging,Medication-related adverse effects as a potential cause of acute confusion,Early dementia diagnosis,Depression causing pseudodementia".split(","),1,"Polypharmacy is a leading cause of delirium in elderly clients. Anticholinergic medications, benzodiazepines, opioids, and drug interactions are common culprits. Medication reconciliation and review with the provider can identify and eliminate offending agents.","Geriatrics","Polypharmacy","Use the Beers Criteria to identify potentially inappropriate medications in elderly clients.","polypharmacy,confusion,medication review,Beers Criteria".split(",")),
  q("RPN-CAT","Geriatrics",4,"An elderly client with moderate dementia becomes increasingly agitated in the evening. The nurse implements:","Physical restraints to prevent injury,Environmental modifications including adequate lighting and consistent routine and redirecting activities,Sedative medications as first-line treatment,Isolation in a quiet dark room".split(","),1,"Sundowning management focuses on non-pharmacological interventions: consistent daily routine, adequate lighting in late afternoon, reducing environmental stimuli, redirecting with calming activities, and maintaining sleep hygiene. Medications are reserved for when non-pharmacological approaches fail.","Geriatrics","Dementia Care","Exposure to bright light during the day and reducing caffeine after noon can help prevent sundowning episodes.","sundowning,dementia,non-pharmacological intervention,agitation".split(",")),

  // === Community Health (3 questions: 1 easy, 1 moderate, 1 difficult) ===
  q("REX-PN","Community Health",1,"The nurse is conducting a community health assessment. Primary prevention activities include:","Screening for hypertension at a community health fair,Providing immunizations and health education about nutrition and exercise,Rehabilitating a client after a stroke,Managing diabetes with insulin therapy".split(","),1,"Primary prevention prevents disease before it occurs: immunizations, health education, lifestyle counseling, safety measures (seatbelts, helmets), and environmental protection. Secondary prevention = early detection (screening). Tertiary prevention = managing existing disease and rehabilitation.","Community Health","Levels of Prevention","Primary = prevent it. Secondary = detect it early. Tertiary = manage and rehabilitate.","primary prevention,immunization,health education,community health".split(",")),
  q("REX-PN","Community Health",3,"The nurse is planning a tuberculosis screening program. The priority population for targeted testing includes:","All adults over age 50,Close contacts of active TB cases and immunocompromised individuals and homeless populations,Athletes and students,Office workers in well-ventilated buildings".split(","),1,"Targeted TB testing focuses on high-risk populations: close contacts of active cases, HIV-positive individuals, immunosuppressed clients, homeless populations, incarcerated individuals, healthcare workers, and immigrants from high-prevalence countries. Universal screening is not recommended.","Community Health","Tuberculosis Control","Latent TB infection: positive skin test, no symptoms, not contagious. Active TB: symptoms present, contagious.","tuberculosis screening,high-risk populations,targeted testing,public health".split(",")),
  q("RPN-CAT","Community Health",4,"A community health nurse identifies a cluster of lead poisoning cases in children in a specific neighborhood. The nurse's priority action is:","Treating individual children with chelation therapy,Investigating environmental lead sources and reporting to public health authorities,Educating parents about lead symptoms only,Waiting for more cases before reporting".split(","),1,"Environmental investigation identifies the source (lead paint, contaminated soil, water pipes) enabling primary prevention for the entire community. Reporting to public health authorities triggers investigation and remediation. Individual treatment is important but does not prevent new cases.","Community Health","Environmental Health","Lead poisoning in children most commonly comes from pre-1978 housing with lead-based paint.","lead poisoning,environmental investigation,public health reporting,community nursing".split(",")),

  // === Ethics/Legal (3 questions: 1 easy, 1 moderate, 1 difficult) ===
  q("REX-PN","Ethics/Legal",1,"A nurse is subpoenaed to testify about a client's care. The nurse should:","Refuse to testify citing client confidentiality,Consult with the facility's legal counsel before testifying,Discuss the case with colleagues before testifying,Provide all information without legal guidance".split(","),1,"When subpoenaed, the nurse should notify the nurse manager and consult with facility legal counsel before testifying. Legal counsel advises on what information can be disclosed, HIPAA protections, and how to respond appropriately during testimony.","Ethics/Legal","Legal Obligations","Only testify to facts documented in the medical record — never speculate or provide opinions unless asked as an expert witness.","subpoena,legal testimony,HIPAA,nursing documentation".split(",")),
  q("REX-PN","Ethics/Legal",3,"A client with decision-making capacity refuses a blood transfusion that the healthcare team believes is life-saving. The ethical principle guiding the nurse's response is:","Beneficence overrides client choice,Autonomy gives the competent client the right to refuse any treatment,Justice requires treating all clients equally,Veracity requires telling the client they are wrong".split(","),1,"Autonomy is the fundamental ethical principle that respects an individual's right to make informed decisions about their own healthcare, even when those decisions conflict with medical recommendations. The nurse ensures the client understands the consequences and documents the refusal.","Ethics/Legal","Ethical Principles","Autonomy may conflict with beneficence — but for competent adults, autonomy prevails.","autonomy,refusal of treatment,ethical principles,informed consent".split(",")),
  q("RPN-CAT","Ethics/Legal",4,"A nurse discovers a colleague has been documenting assessments that were never performed. The nurse should:","Confront the colleague and keep it confidential,Report the falsification through proper institutional channels as this constitutes fraud,Ignore it as it is not the nurse's responsibility,Ask the colleague to correct the records quietly".split(","),1,"Falsification of medical records is fraud, a criminal offense, and a violation of professional nursing standards. It endangers patients by creating inaccurate medical histories. The nurse has an ethical and legal obligation to report through institutional channels and may need to report to the board of nursing.","Ethics/Legal","Documentation Integrity","Falsifying medical records is grounds for license revocation, termination, and criminal prosecution.","documentation fraud,reporting obligation,professional ethics,patient safety".split(",")),

  // === Delegation (3 questions: 1 easy, 1 moderate, 1 difficult) ===
  q("REX-PN","Delegation",1,"The RPN is working with a nursing assistant (UAP). Which task is appropriate to delegate?","Teaching a newly diagnosed diabetic client about insulin injection,Assisting a stable client with bathing and feeding,Performing a focused respiratory assessment on a client with pneumonia,Administering oral medications to a stable client".split(","),1,"UAPs can perform routine tasks on stable clients: bathing, feeding, ambulation, toileting, vital signs on stable clients, and intake/output measurement. Assessment, teaching, medication administration, and care planning are NOT within UAP scope and cannot be delegated.","Delegation","Scope of Practice","Delegate routine tasks on STABLE clients only. Any change in condition requires RPN reassessment.","delegation,UAP,scope of practice,stable clients".split(",")),
  q("REX-PN","Delegation",3,"The RPN receives shift report on four clients. Which client should the RPN assess first?","A client with a blood glucose of 180 mg/dL before lunch,A client with a newly applied cast reporting numbness and tingling in the fingers,A client who is 2 days post-appendectomy requesting pain medication,A stable client requesting discharge paperwork".split(","),1,"Numbness and tingling after cast application indicates potential neurovascular compromise (compartment syndrome). This is an emergency requiring immediate assessment (5 Ps) and possible cast bivalving. The ABCs and Maslow's hierarchy guide prioritization: life-threatening and limb-threatening conditions first.","Delegation","Priority Setting","Use the ABCs framework: Airway > Breathing > Circulation. Then: unstable > acute > stable.","prioritization,neurovascular compromise,cast complication,nursing assessment".split(",")),
  q("RPN-CAT","Delegation",4,"An RPN delegates vital sign measurement to a UAP for a client who was stable but recently received a new antihypertensive medication. This delegation is:","Appropriate since the client was previously stable,Inappropriate because the client's condition has changed and requires nursing assessment of medication response,Appropriate if the UAP has taken vital signs before,A matter of personal preference".split(","),1,"When a client's condition changes (new medication affecting vital signs), the RPN should perform the initial assessment to evaluate the therapeutic response and watch for adverse effects. Once the client is confirmed stable on the new medication, future vital sign monitoring may be delegated.","Delegation","Delegation Decision-Making","Delegation appropriateness changes with client condition — reassess delegation decisions when the clinical picture changes.","delegation,medication monitoring,clinical judgment,antihypertensive".split(",")),

  // === Health Promotion (2 questions: 1 easy, 1 moderate) ===
  q("REX-PN","Health Promotion",1,"The nurse recommends colon cancer screening for average-risk adults beginning at age:","40,45 with colonoscopy or stool-based testing,55,65".split(","),1,"The American Cancer Society recommends colon cancer screening beginning at age 45 for average-risk adults. Options include colonoscopy every 10 years, FIT annually, or stool DNA test every 3 years. Earlier screening for those with family history or risk factors.","Health Promotion","Cancer Screening","The screening age was lowered from 50 to 45 in 2021 — this is a frequently updated guideline.","colon cancer screening,colonoscopy,FIT,cancer prevention".split(",")),
  q("REX-PN","Health Promotion",3,"A nurse is designing a smoking cessation program. The most effective approach combines:","Nicotine replacement therapy alone,Behavioral counseling with pharmacotherapy such as varenicline or NRT,Willpower-based quitting without any assistance,Reducing to one cigarette per day".split(","),1,"Combination therapy (behavioral counseling + pharmacotherapy) has the highest quit rates. Varenicline (Chantix) is the most effective single agent. NRT (patch, gum, lozenge) and bupropion are alternatives. Brief counseling interventions by nurses at every visit are effective.","Health Promotion","Smoking Cessation","Ask, Advise, Assess, Assist, Arrange — the 5 A's of smoking cessation counseling at every clinical encounter.","smoking cessation,varenicline,NRT,behavioral counseling".split(",")),

  // === Nutrition (2 questions: 1 easy, 1 moderate) ===
  q("REX-PN","Nutrition",3,"A client with chronic kidney disease should limit which nutrient in their diet?","Carbohydrates,Potassium to prevent cardiac dysrhythmias,Vitamin C,Unsaturated fats".split(","),1,"CKD impairs potassium excretion, causing dangerous hyperkalemia that can lead to fatal cardiac dysrhythmias. High-potassium foods to avoid include bananas, oranges, potatoes, tomatoes, and salt substitutes. Phosphorus and sodium are also restricted.","Nutrition","Renal Diet","Salt substitutes contain potassium chloride — these are dangerous for CKD clients. Always check labels.","CKD diet,potassium restriction,hyperkalemia,dietary modification".split(",")),
  q("REX-PN","Nutrition",5,"A client receiving enteral tube feeding has a residual volume of 350 mL. The nurse should:","Continue the feeding at the current rate,Hold the feeding and reassess per institutional protocol as this volume suggests delayed gastric emptying,Increase the feeding rate,Discard the residual and restart".split(","),1,"High residual volumes (typically > 250-500 mL depending on facility protocol) indicate delayed gastric emptying and increase aspiration risk. Hold the feeding, return the aspirate (contains electrolytes), reassess in 30-60 minutes, and consider prokinetic agents.","Nutrition","Enteral Feeding Management","Return the aspirated residual to prevent electrolyte loss. Elevate HOB 30-45 degrees during and 30 minutes after feeding.","enteral feeding,gastric residual,aspiration prevention,tube feeding".split(",")),

  // === Wound Care (2 questions: 1 easy, 1 moderate) ===
  q("REX-PN","Wound Care",3,"The nurse is changing a sterile dressing. Which action breaks sterile technique?","Opening the sterile package away from the body,Reaching across the sterile field to grab an item on the other side,Keeping sterile items above waist level,Using sterile gloves to handle supplies".split(","),1,"Reaching across a sterile field contaminates it with unsterile clothing or arms. The outer 1-inch border of the sterile field is considered contaminated. Sterile items below the waist are also considered contaminated. If sterility is questioned, the field should be replaced.","Wound Care","Sterile Technique","When in doubt about sterility, consider it contaminated. It is always safer to set up a new sterile field.","sterile technique,wound dressing,contamination,asepsis".split(",")),
  q("REX-PN","Wound Care",5,"A client with a deep wound has an order for wet-to-dry dressings. The nurse understands this type of dressing is used for:","Promoting moisture retention in clean wounds,Mechanical debridement of necrotic tissue,Covering a sutured surgical incision,Applying negative pressure to the wound".split(","),1,"Wet-to-dry dressings provide mechanical debridement: moist gauze is applied to the wound bed, allowed to dry, then removed — pulling off adherent necrotic tissue and debris. This technique is non-selective (removes healthy tissue too) and is being replaced by more targeted debridement methods.","Wound Care","Wound Debridement","Wet-to-dry dressings are falling out of favor due to non-selective tissue removal — moist wound healing with selective debridement is preferred.","wet-to-dry dressing,debridement,wound care,necrotic tissue".split(",")),
];

async function main() {
  let inserted = 0;
  const batchSize = 50;
  for (let i = 0; i < QS.length; i += batchSize) {
    const batch = QS.slice(i, i + batchSize);
    const values: string[] = [];
    const params: any[] = [];
    let idx = 1;
    for (const q of batch) {
      values.push(`($${idx},$${idx+1},$${idx+2},$${idx+3},$${idx+4},$${idx+5}::jsonb,$${idx+6}::jsonb,$${idx+7},$${idx+8}::integer,$${idx+9},$${idx+10},$${idx+11},$${idx+12},$${idx+13},$${idx+14},$${idx+15}::text[])`);
      params.push(q.tier,q.exam,q.qt,q.status,q.stem,JSON.stringify(q.options),JSON.stringify(q.correct),q.rationale,q.diff,q.bs,q.rs,q.sh,q.topic,q.subtopic,q.clinicalPearl,`{${q.tags.map(t => `"${t}"`).join(",")}}`);
      idx += 16;
    }
    const sql = `INSERT INTO exam_questions (tier, exam, question_type, status, stem, options, correct_answer, rationale, difficulty, body_system, region_scope, stem_hash, topic, subtopic, clinical_pearl, tags)
                 SELECT v.* FROM (VALUES ${values.join(",")}) AS v(tier,exam,question_type,status,stem,options,correct_answer,rationale,difficulty,body_system,region_scope,stem_hash,topic,subtopic,clinical_pearl,tags)
                 WHERE NOT EXISTS (SELECT 1 FROM exam_questions e WHERE e.stem_hash = v.stem_hash)`;
    const result = await pool.query(sql, params);
    inserted += result.rowCount || 0;
  }
  console.log(`[RPN-B6] Inserted ${inserted}/${QS.length}`);
  const counts = await pool.query(`SELECT tier, count(*) as cnt FROM exam_questions WHERE status='published' GROUP BY tier ORDER BY tier`);
  counts.rows.forEach((r: any) => console.log(`  ${r.tier}: ${r.cnt}`));
  const topicCounts = await pool.query(`SELECT topic, count(*) as cnt FROM exam_questions WHERE status='published' AND tier='rpn' AND topic IS NOT NULL GROUP BY topic ORDER BY topic`);
  console.log(`\n  RPN Topics:`);
  topicCounts.rows.forEach((r: any) => console.log(`    ${r.topic}: ${r.cnt}`));
  await pool.end();
}
main().catch(e => { console.error(e); process.exit(1); });
